import {
  autoInjectIfNeeded,
  delay,
  deriveVideoState,
  ensureModifierInjectionForActiveTab,
  injectClipper,
  refreshSelectionModifierInjection,
  setupContextMenus,
  isVideoUrl
} from './contextMenusCoordinator';
import {
  createContextMenuRuntimeState,
  type ContextMenuListenerDependencies
} from './contextMenusTypes';

const runtimeState = createContextMenuRuntimeState();
let listenerDependencies: ContextMenuListenerDependencies | null = null;

export function createContextMenuListenerDependencies(
  dependencies: ContextMenuListenerDependencies
): ContextMenuListenerDependencies {
  return dependencies;
}

function getDependencies(): ContextMenuListenerDependencies {
  if (!listenerDependencies) {
    throw new Error('[contextMenus] Dependencies have not been configured.');
  }
  return listenerDependencies;
}

export function registerContextMenuListeners(dependencies: ContextMenuListenerDependencies): void {
  listenerDependencies = dependencies;

  const {
    action,
    contextMenus,
    runtime,
    tabs,
    messaging,
    optionsRepository
  } = dependencies;

  runtime.onInstalled(() => {
    void setupContextMenus(dependencies, runtimeState);
  });

  runtime.onStartup(() => {
    void setupContextMenus(dependencies, runtimeState);
  });

  // Ensure menus exist even if startup event is unavailable.
  void setupContextMenus(dependencies, runtimeState);

  action.onClicked(async (tab) => {
    if (!tab?.id) {
      return;
    }
    try {
      await injectClipper(dependencies, runtimeState, tab.id, { targetFrameId: 0 });
      await delay(50);
      await tabs.sendMessage(tab.id, { action: 'clipFull' });
    } catch (error) {
      console.error('[action] Failed to trigger clipFull:', error);
    }
  });

  contextMenus.onClicked(async (info, tab) => {
    if (!tab?.id) {
      return;
    }

    const frameId = typeof info.frameId === 'number' ? info.frameId : 0;
    const candidateUrl = tab.url ?? info.pageUrl ?? null;
    const isVideo = typeof tab.id === 'number'
      ? deriveVideoState(dependencies, runtimeState, tab.id, candidateUrl)
      : isVideoUrl(candidateUrl);

    let actionType: 'clipFull' | 'clipSelection' | 'videoClipSelection' | 'startVideoMode' | null = null;
    let waitMs = 50;
    let targetFrameId: number | undefined = 0;

    switch (info.menuItemId) {
      case 'clip-page':
        if (isVideo) {
          actionType = 'startVideoMode';
          waitMs = 120;
        } else {
          actionType = 'clipFull';
        }
        targetFrameId = 0;
        break;
      case 'clip-selection':
        actionType = isVideo ? 'videoClipSelection' : 'clipSelection';
        waitMs = isVideo ? 120 : 100;
        targetFrameId = frameId;
        break;
      case 'clip-video':
        actionType = 'startVideoMode';
        waitMs = 120;
        targetFrameId = 0;
        break;
      default:
        break;
    }

    if (!actionType || targetFrameId === undefined) {
      return;
    }

    if (targetFrameId !== 0) {
      await injectClipper(dependencies, runtimeState, tab.id, { targetFrameId: 0, silent: true });
    }
    await injectClipper(dependencies, runtimeState, tab.id, { targetFrameId });
    await delay(waitMs);

    try {
      await tabs.sendMessage(tab.id, { action: actionType, frameId: targetFrameId, tabId: tab.id }, { frameId: targetFrameId });
    } catch (error) {
      console.error('[contextMenu] Failed to dispatch action to tab:', error);
    }
  });

  contextMenus.onShown((info, tab) => {
    const selectionText = typeof info.selectionText === 'string' ? info.selectionText.trim() : '';
    const hasSelection = selectionText.length > 0;
    const candidateUrl = tab?.url ?? info.pageUrl ?? null;
    const isVideo = typeof tab?.id === 'number'
      ? deriveVideoState(dependencies, runtimeState, tab.id, candidateUrl)
      : isVideoUrl(candidateUrl);

    const selectionTitle = hasSelection && isVideo
      ? runtimeState.clipSelectionVideoTitle || runtimeState.clipSelectionDefaultTitle
      : runtimeState.clipSelectionDefaultTitle;
    const pageTitle = isVideo ? runtimeState.videoModeTitle : runtimeState.clipFullPageTitle;

    void contextMenus.update('clip-selection', { title: selectionTitle }).catch(() => {});
    void contextMenus.update('clip-page', { title: pageTitle }).catch(() => {});
    contextMenus.refresh?.();
  });

  messaging.addListener((rawMessage, sender) => {
    if (!rawMessage || typeof rawMessage !== 'object') {
      return undefined;
    }
    const message = rawMessage as { type?: unknown; payload?: unknown };
    if (message.type !== 'AIIOB_FORWARD_VIDEO_SELECTION') {
      return undefined;
    }

    const tabId = sender.tabId;
    if (typeof tabId !== 'number') {
      return { success: false, error: 'NO_TAB' };
    }

    const rawPayload = (typeof message.payload === 'object' && message.payload !== null)
      ? message.payload as Record<string, unknown>
      : {};

    const payload = {
      selectedHtml: String(rawPayload.selectedHtml ?? ''),
      selectedText: String(rawPayload.selectedText ?? ''),
      sourceFrameId: sender.frameId ?? null,
      sourceUrl: typeof rawPayload.sourceUrl === 'string' ? rawPayload.sourceUrl : null
    } as const;

    return tabs.sendMessage(tabId, { action: 'videoClipSelectionFromFrame', payload }, { frameId: 0 })
      .then(() => ({ success: true }))
      .catch((error) => {
        const msg = error instanceof Error ? error.message : String(error);
        console.error('[contextMenu] Failed to forward video selection from frame:', msg);
        return { success: false, error: msg };
      });
  });

  optionsRepository.onChange(() => {
    void refreshSelectionModifierInjection(runtimeState)
      .then(() => ensureModifierInjectionForActiveTab(dependencies, runtimeState))
      .catch(() => {
        // ignore refresh failures; state will retry on next update
      });
  });

  tabs.onActivated(({ tabId }) => {
    void tabs.get(tabId).then((tab) => {
      void autoInjectIfNeeded(dependencies, runtimeState, tabId, tab?.url);
    }).catch(() => {});
  });

  tabs.onUpdated((tabId, changeInfo, tab) => {
    if (changeInfo.status === 'loading') {
      runtimeState.autoInjectedTabs.delete(tabId);
    }
    if (changeInfo.status === 'complete' || typeof changeInfo.url === 'string') {
      const candidateUrl = changeInfo.url ?? tab.url;
      if (changeInfo.status === 'complete' || isVideoUrl(candidateUrl)) {
        void autoInjectIfNeeded(dependencies, runtimeState, tabId, candidateUrl);
      }
    }
  });

  tabs.onRemoved((tabId) => {
    runtimeState.tabVideoState.delete(tabId);
    runtimeState.autoInjectedTabs.delete(tabId);
  });
}

import type { Options } from '../store';
import type { OllamaChatResponse, OpenAIChatCompletionResponse } from '../../shared/types';
import { AppError, classifierErrors } from '../../shared/errors';
import { ClassificationRequestSchema } from '../../shared/schemas';

type ClassifierConfig = NonNullable<Options['classifier']>;
type ClassifierProvider = ClassifierConfig['provider'];

declare const fetch: typeof globalThis.fetch;

interface ClassificationMeta {
  typeHint: string;
  platform: string;
  url: string;
  title: string;
}

const DEFAULT_TIMEOUT_MS = 15_000;

export type ClassifierError = AppError;
export type ClassifierErrorCode = ClassifierError['code'];

export interface ClassifierSuccess {
  ok: true;
  payload: Record<string, unknown>;
}

export interface ClassifierFailure {
  ok: false;
  error: ClassifierError;
}

export type ClassifierResponse = ClassifierSuccess | ClassifierFailure;

type PostJsonSuccess<T> = {
  ok: true;
  data: T;
};

type PostJsonFailure = {
  ok: false;
  error: ClassifierError;
};

type PostJsonResult<T> = PostJsonSuccess<T> | PostJsonFailure;

export async function classify(
  cfg: ClassifierConfig,
  meta: ClassificationMeta,
  preview: string
): Promise<ClassifierResponse> {
  const request = ClassificationRequestSchema.parse({
    ...meta,
    preview
  });
  const taxonomy = cfg.taxonomy ?? {};
  const sys = `你是一个严格的JSON分类器。taxonomy=${JSON.stringify(taxonomy)}。输出JSON: {type, topics, ai_platform, tags}`;
  const user = `meta=${JSON.stringify({
    typeHint: request.typeHint,
    platform: request.platform,
    url: request.url,
    title: request.title
  })}\npreview:\n${request.preview}`;

  if (cfg.provider === 'ollama') {
    const endpoint = cfg.endpoint || 'http://localhost:11434/api/chat';
    const response = await postJson<OllamaChatResponse>(
      endpoint,
      {
        model: cfg.model || 'llama3.1',
        stream: false,
        messages: [
          { role: 'system', content: sys },
          { role: 'user', content: user }
        ]
      },
      {},
      'ollama'
    );

    if (response.ok) {
      const content = response.data?.message?.content;
      return parseClassifierPayload(content, cfg.provider, endpoint);
    }

    const { error } = response as PostJsonFailure;
    return {
      ok: false,
      error
    };
  }

  const endpoint = cfg.endpoint || 'https://api.openai.com/v1/chat/completions';
  const response = await postJson<OpenAIChatCompletionResponse>(
    endpoint,
    {
      model: cfg.model,
      messages: [
        { role: 'system', content: sys },
        { role: 'user', content: user }
      ],
      temperature: 0
    },
    {
      'Content-Type': 'application/json',
      Authorization: `Bearer ${cfg.apiKey || ''}`
    },
    cfg.provider
  );

  if (response.ok) {
    const content = response.data?.choices?.[0]?.message?.content;
    return parseClassifierPayload(content, cfg.provider, endpoint);
  }

  const { error } = response as PostJsonFailure;
  return {
    ok: false,
    error
  };
}

async function postJson<T>(
  endpoint: string,
  body: unknown,
  headers: Record<string, string> = {},
  provider: ClassifierProvider
): Promise<PostJsonResult<T>> {
  const controller = new AbortController();
  const timeout = setTimeout(() => controller.abort(), DEFAULT_TIMEOUT_MS);

  try {
    const response = await fetch(endpoint, {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        ...headers
      },
      body: JSON.stringify(body),
      signal: controller.signal
    });

    if (!response.ok) {
      const text = await safeReadText(response);
      return {
        ok: false,
        error: classifierErrors.transportFailure(
          text || `HTTP ${response.status}`,
          {
            provider,
            endpoint,
            status: response.status,
            method: 'POST'
          }
        )
      };
    }

    try {
      const json = (await response.json()) as T;
      return {
        ok: true,
        data: json
      };
    } catch (error) {
      return {
        ok: false,
        error: classifierErrors.invalidPayload(
          'Classifier response is not valid JSON',
          {
            provider,
            endpoint
          },
          { cause: error }
        )
      };
    }
  } catch (error) {
    if (error instanceof Error && error.name === 'AbortError') {
      return {
        ok: false,
        error: classifierErrors.timeout(
          {
            provider,
            endpoint
          },
          { cause: error }
        )
      };
    }
    return {
      ok: false,
      error: classifierErrors.transportFailure(
        error instanceof Error ? error.message : String(error),
        {
          provider,
          endpoint
        },
        { cause: error }
      )
    };
  } finally {
    clearTimeout(timeout);
  }
}

async function safeReadText(response: Response): Promise<string> {
  try {
    return await response.text();
  } catch {
    return '';
  }
}

function parseClassifierPayload(
  payload: string | undefined,
  provider: ClassifierProvider,
  endpoint: string
): ClassifierResponse {
  if (!payload) {
    return {
      ok: false,
      error: classifierErrors.invalidPayload(
        `Classifier response from ${provider} did not include content`,
        {
          provider,
          endpoint
        }
      )
    };
  }

  try {
    const parsed: unknown = JSON.parse(payload);
    if (!isRecord(parsed)) {
      return {
        ok: false,
        error: classifierErrors.invalidPayload(
          `Classifier response from ${provider} is not a JSON object`,
          {
            provider,
            endpoint,
            payloadSample: payload
          }
        )
      };
    }
    return {
      ok: true,
      payload: parsed
    };
  } catch (error) {
    return {
      ok: false,
      error: classifierErrors.invalidPayload(
        `Classifier response from ${provider} is not valid JSON`,
        {
          provider,
          endpoint,
          payloadSample: payload
        },
        { cause: error }
      )
    };
  }
}

function isRecord(value: unknown): value is Record<string, unknown> {
  return typeof value === 'object' && value !== null && !Array.isArray(value);
}

import type { Options } from '../store';
import type { ClipPayload } from '../../shared/types';
import { classify } from '../llm/classifier';
import type { ClassifierFailure, ClassifierResponse } from '../llm/classifier';
import { AppError, classifierErrors, errorHandler } from '../../shared/errors';
import { ClassificationResultSchema } from '../../shared/schemas';
import type { ClassificationResult as ClassificationResultT } from '../../shared/schemas';

// Re-export narrowed result type from schemas to keep public API stable
export type { ClassificationResult } from '../../shared/schemas';

const CLASSIFICATION_PREVIEW_LENGTH = 4000;

export function createClassificationPreview(payload: ClipPayload): string {
  return payload.markdown.slice(0, CLASSIFICATION_PREVIEW_LENGTH);
}

export async function classifyClip(options: Options, payload: ClipPayload): Promise<ClassificationResultT> {
  const fallbackBase: ClassificationResultT = ClassificationResultSchema.parse({
    topics: [],
    tags: [],
    status: 'fallback' as const,
    ...(payload.type !== undefined && { type: payload.type }),
    ...(payload.meta?.platform !== undefined && { ai_platform: payload.meta.platform })
  });

  if (!options.classifier?.enabled) {
    return { ...fallbackBase, fallbackReason: 'disabled' as const } as ClassificationResultT;
  }

  try {
    const preview = createClassificationPreview(payload);
    const response = await classify(options.classifier, {
      typeHint: payload.type || 'article',
      platform: payload.meta?.platform || 'unknown',
      url: payload.meta?.url || '',
      title: payload.title || 'Untitled'
    }, preview);

    if (response.ok) {
      return normalizeClassificationPayload(response, fallbackBase);
    }

    const { error } = response as ClassifierFailure;
    await errorHandler.handle(error, { suppressNotifications: true });
    return ClassificationResultSchema.parse({
      ...fallbackBase,
      fallbackReason: 'error' as const,
      errorDetail: error
    }) as ClassificationResultT;
  } catch (error) {
    const errorDetail = classifierErrors.transportFailure(
      error instanceof Error ? error.message : String(error),
      {
        provider: options.classifier.provider,
        endpoint: options.classifier.endpoint
      },
      { cause: error }
    );
    await errorHandler.handle(errorDetail, { suppressNotifications: true });
    return ClassificationResultSchema.parse({
      ...fallbackBase,
      fallbackReason: 'error' as const,
      errorDetail
    }) as ClassificationResultT;
  }
}

function normalizeClassificationPayload(
  response: Extract<ClassifierResponse, { ok: true }>,
  fallbackBase: ClassificationResultT
): ClassificationResultT {
  const payload = response.payload;
  const normalized: ClassificationResultT = {
    ...fallbackBase,
    status: 'success'
  };

  if (typeof payload.type === 'string') {
    normalized.type = payload.type;
  }

  if (typeof payload.ai_platform === 'string') {
    normalized.ai_platform = payload.ai_platform;
  }

  if (Array.isArray(payload.topics)) {
    normalized.topics = payload.topics.filter(isString);
  } else {
    normalized.topics = fallbackBase.topics ?? [];
  }

  if (Array.isArray(payload.tags)) {
    normalized.tags = payload.tags.filter(isString);
  } else {
    normalized.tags = fallbackBase.tags ?? [];
  }

  for (const [key, value] of Object.entries(payload)) {
    if (key === 'type' || key === 'ai_platform' || key === 'topics' || key === 'tags') {
      continue;
    }
    (normalized as Record<string, unknown>)[key] = value;
  }

  // Validate final shape but keep passthrough extras
  return ClassificationResultSchema.parse(normalized);
}

function isString(value: unknown): value is string {
  return typeof value === 'string';
}

import { getMessages, formatMessage } from '../../i18n';
import { APP_ICON_PATH } from '../../shared/constants';
import type { NotificationOptions as PlatformNotificationOptions } from '../../platform/interfaces/notifications';
import type { NotificationsService } from '../../platform/interfaces/notifications';
import type { RuntimeService } from '../../platform/interfaces/runtime';
import type { PlatformServices } from '../../platform/types';
import type {
  AppNotification,
  NotificationAdapter,
  NotificationChannel,
  NotificationSeverity,
  NormalizedNotification
} from '../../shared/notifications/types';
import { AppError, ErrorSeverity, getErrorHandler, notificationErrors } from '../../shared/errors';
import { getService } from '../../shared/di';
import { TOKENS } from '../../shared/di/tokens';

export type {
  AppNotification,
  NotificationAdapter,
  NotificationChannel,
  NotificationSeverity,
  NormalizedNotification
} from '../../shared/notifications/types';

const NOTIFICATION_CHANNELS = {
  clipSuccess: 'clipper.success' as const,
  clipFailure: 'clipper.failure' as const,
  clipError: 'clipper.error' as const,
  clipWarning: 'clipper.warning' as const,
  injectionFailure: 'clipper.injection' as const,
  systemError: 'system.error' as const,
  systemWarning: 'system.warning' as const,
  systemInfo: 'system.info' as const,
  systemState: 'system.state' as const,
  userFacing: 'system.user' as const,
  developer: 'system.developer' as const
};

type KnownNotificationChannel = typeof NOTIFICATION_CHANNELS[keyof typeof NOTIFICATION_CHANNELS];

let customNotificationAdapter: NotificationAdapter | null = null;

const TEMPLATE_BASIC: PlatformNotificationOptions['type'] =
  (typeof chrome !== 'undefined' && chrome.notifications?.TemplateType)
    ? chrome.notifications.TemplateType.BASIC
    : 'basic';

const SEVERITY_TEMPLATE_MAP: Record<NotificationSeverity, PlatformNotificationOptions['type']> = {
  success: TEMPLATE_BASIC,
  info: TEMPLATE_BASIC,
  warning: TEMPLATE_BASIC,
  error: TEMPLATE_BASIC,
  critical: TEMPLATE_BASIC
};

const ERROR_SEVERITY_TO_NOTIFICATION: Record<ErrorSeverity, NotificationSeverity> = {
  [ErrorSeverity.INFO]: 'info',
  [ErrorSeverity.WARNING]: 'warning',
  [ErrorSeverity.ERROR]: 'error',
  [ErrorSeverity.CRITICAL]: 'critical'
};

const SEVERITY_TITLE_MAP: Record<NotificationSeverity, string> = {
  success: 'All-in-Obsidian — Success',
  info: 'All-in-Obsidian — Info',
  warning: 'All-in-Obsidian — Warning',
  error: 'All-in-Obsidian — Error',
  critical: 'All-in-Obsidian — Critical'
};

export { NOTIFICATION_CHANNELS };
export const CHANNEL_USER_FACING = NOTIFICATION_CHANNELS.userFacing;
export const CHANNEL_DEVELOPER = NOTIFICATION_CHANNELS.developer;

export function setNotificationAdapter(adapter: NotificationAdapter | null): void {
  customNotificationAdapter = adapter;
}

function getNotificationPlatformServices(): Pick<PlatformServices, 'runtime' | 'notifications'> {
  const platform = getService<PlatformServices>(TOKENS.platformServices);
  return {
    runtime: platform.runtime,
    notifications: platform.notifications
  };
}

function sanitizeChannel(channel: NotificationChannel): string {
  return channel.replace(/[^a-z0-9]+/gi, '-');
}

function createNotificationId(channel: NotificationChannel, tag?: string): string {
  const base = sanitizeChannel(channel);
  const suffix = tag ?? `${Date.now()}`;
  return `${base}-${suffix}`;
}

function resolveIconUrl(iconUrl?: string): string {
  if (!iconUrl) {
    return APP_ICON_PATH;
  }
  if (/^(?:https?:|data:)/.test(iconUrl)) {
    return iconUrl;
  }
  try {
    return getNotificationPlatformServices().runtime.getURL(iconUrl);
  } catch (error) {
    const globalObj = globalThis as { process?: { env?: Record<string, unknown> } } | undefined;
    if (globalObj?.process?.env && 'VITEST_WORKER_ID' in globalObj.process.env) {
      return `chrome-extension://test/${iconUrl}`;
    }
    if (typeof document !== 'undefined' && document.baseURI.startsWith('about:')) {
      return `chrome-extension://test/${iconUrl}`;
    }
    console.warn('[notifications] Failed to resolve icon URL', error);
    return iconUrl;
  }
}

function resolveTemplateType(severity: NotificationSeverity): PlatformNotificationOptions['type'] {
  return SEVERITY_TEMPLATE_MAP[severity] ?? TEMPLATE_BASIC;
}

function normalizeNotificationPayload(payload: AppNotification): NormalizedNotification {
  return {
    ...payload,
    type: resolveTemplateType(payload.severity),
    iconUrl: resolveIconUrl(payload.iconUrl),
    timestamp: Date.now()
  };
}

function toNotificationOptions(payload: NormalizedNotification): PlatformNotificationOptions {
  const result: PlatformNotificationOptions = {
    type: payload.type,
    iconUrl: payload.iconUrl,
    title: payload.title,
    message: payload.message
  };

  if (payload.contextMessage !== undefined) {
    result.contextMessage = payload.contextMessage;
  }

  if (payload.requireInteraction !== undefined) {
    result.requireInteraction = payload.requireInteraction;
  }

  return result;
}

function createNotificationMetadata(error: AppError): Record<string, unknown> {
  const metadata: Record<string, unknown> = {
    code: error.code,
    domain: error.domain,
    recoverable: error.recoverable,
    severity: error.severity
  };
  if (error.context) {
    metadata.context = error.context;
  }
  if (error.timestamp) {
    metadata.timestamp = error.timestamp;
  }
  return metadata;
}

async function mapErrorToNotification(error: AppError): Promise<AppNotification | null> {
  const severity = ERROR_SEVERITY_TO_NOTIFICATION[error.severity] ?? 'error';
  const message = error.userMessage ?? error.message;
  const metadata = createNotificationMetadata(error);

  if ((error.domain === 'extraction' || error.domain === 'content') && (severity === 'error' || severity === 'critical')) {
    const msgs = await getMessages();
    const result: AppNotification = {
      channel: NOTIFICATION_CHANNELS.clipFailure,
      severity,
      iconUrl: APP_ICON_PATH,
      title: msgs.clipFailed,
      message,
      requireInteraction: !error.recoverable,
      tag: error.code,
      metadata
    };

    const contextMessage = error.message && error.message !== message ? error.message : undefined;
    if (contextMessage !== undefined) {
      result.contextMessage = contextMessage;
    }

    return result;
  }

  if ((error.domain === 'extraction' || error.domain === 'content') && severity === 'warning') {
    const msgs = await getMessages();
    const reason = message;
    const result: AppNotification = {
      channel: NOTIFICATION_CHANNELS.clipWarning,
      severity,
      iconUrl: APP_ICON_PATH,
      title: msgs.classificationFallbackTitle,
      message: formatMessage(msgs.classificationFallbackMessage, { reason }),
      requireInteraction: false,
      tag: error.code,
      metadata: {
        ...metadata,
        reason
      }
    };

    const contextMessage = error.message && error.message !== reason ? error.message : undefined;
    if (contextMessage !== undefined) {
      result.contextMessage = contextMessage;
    }

    return result;
  }

  if (error.domain === 'i18n' || error.domain === 'options') {
    const result: AppNotification = {
      channel: NOTIFICATION_CHANNELS.userFacing,
      severity,
      iconUrl: APP_ICON_PATH,
      title: SEVERITY_TITLE_MAP[severity],
      message,
      requireInteraction: severity === 'error' || severity === 'critical',
      tag: error.code,
      metadata
    };

    const contextMessage = error.message && error.message !== message ? error.message : undefined;
    if (contextMessage !== undefined) {
      result.contextMessage = contextMessage;
    }

    return result;
  }

  const channel =
    severity === 'warning'
      ? NOTIFICATION_CHANNELS.systemWarning
      : severity === 'info'
        ? NOTIFICATION_CHANNELS.systemInfo
        : NOTIFICATION_CHANNELS.systemError;

  const result: AppNotification = {
    channel,
    severity,
    iconUrl: APP_ICON_PATH,
    title: SEVERITY_TITLE_MAP[severity],
    message,
    requireInteraction: severity === 'error' || severity === 'critical',
    tag: error.code,
    metadata
  };

  const contextMessage = error.message && error.message !== message ? error.message : undefined;
  if (contextMessage !== undefined) {
    result.contextMessage = contextMessage;
  }

  return result;
}

async function dispatchNotification(payload: AppNotification): Promise<string | void> {
  const id = createNotificationId(payload.channel, payload.tag);
  const normalized = normalizeNotificationPayload(payload);

  if (customNotificationAdapter) {
    return customNotificationAdapter(id, normalized);
  }

  return getNotificationPlatformServices().notifications.create(id, toNotificationOptions(normalized));
}

export async function notifyAppEvent(payload: AppNotification): Promise<string | void> {
  return dispatchNotification(payload);
}

function mapChannelForClipper(channel: KnownNotificationChannel): NotificationChannel {
  return channel;
}

export async function notifyClipSuccess(filePath: string, vaultName?: string): Promise<void> {
  const msgs = await getMessages();
  const title = vaultName ? `${msgs.clipSuccess} (${vaultName})` : msgs.clipSuccess;
  await notifyAppEvent({
    channel: mapChannelForClipper(NOTIFICATION_CHANNELS.clipSuccess),
    severity: 'success',
    iconUrl: APP_ICON_PATH,
    title,
    message: String(filePath),
    metadata: {
      filePath,
      vaultName
    }
  });
}

export async function notifyClipFailure(error: string): Promise<void> {
  const msgs = await getMessages();
  await notifyAppEvent({
    channel: mapChannelForClipper(NOTIFICATION_CHANNELS.clipFailure),
    severity: ErrorSeverity.ERROR,
    iconUrl: APP_ICON_PATH,
    title: msgs.clipFailed,
    message: error,
    metadata: { error }
  });
}

