if (markContentRuntimeInitialized(document)) {
  initializeClipperRuntime();
}

function initializeClipperRuntime(): void {
  // 引导内容脚本的依赖注入系统
  const platform = getPlatformServices();
  registerRepositories({
    storage: platform.storage,
    messaging: platform.messaging,
    tabs: platform.tabs,
    runtime: platform.runtime
  });
  configureContentBootstrapStorage(platform.storage);
  bootstrapContentScript();
  const { messaging } = platform;
  const primaryOptionsRepository = resolveRepository<IOptionsRepository>(
    DI_TOKENS.IOptionsRepository
  );
  const runtimeState = createContentRuntimeState({
    optionsRepository: primaryOptionsRepository,
    window
  });
  const clipPromptGateway = createClipperDialogPromptGateway();
  const supportPrompt = createLazySupportPrompt(document);
  const createReaderSession = createLazyReaderSessionFactory({
    document,
    optionsRepository: primaryOptionsRepository,
    storage: platform.storage,
    messaging: platform.messaging,
    runtime: platform.runtime,
    promptGateway: clipPromptGateway
  });
  const createVideoSession = createLazyVideoSessionFactory({
    document,
    optionsRepository: primaryOptionsRepository,
    storage: platform.storage,
    messaging: platform.messaging,
    runtime: platform.runtime
  });
  const selectionController = createSelectionController({
    prompt: clipPromptGateway,
    optionsRepository: primaryOptionsRepository,
    createReaderSession,
    createVideoSession
  });
  const extractorRegistry = createLazyExtractorRegistry(primaryOptionsRepository);
  const selectionTracker = createContentSelectionTracker({
    document,
    window,
    getLastSelectionSnapshot: () => runtimeState.getLastSelectionSnapshot(),
    setLastSelectionSnapshot: (snapshot) => {
      runtimeState.setLastSelectionSnapshot(snapshot);
    }
  });
  // composition below moved to runtime/bootstrapRuntime

  void runtimeState.refreshFragmentConfig();
  void initializeVideoPromptOnDemand(
    {
      optionsRepository: primaryOptionsRepository,
      storage: platform.storage,
      runtime: platform.runtime
    },
    window.location.href
  );

  const runtime = createContentRuntime({
    document,
    window,
    messaging,
    runtimeState,
    selectionTracker,
    selectionController,
    extractorRegistry,
    createRouter: (runClip) =>
      createContentMessageRouter({
        document,
        window,
        messaging,
        supportPrompt,
        setClipMode: (mode) => runtimeState.setClipMode(mode),
        runClip,
        selectionController,
        createVideoSession: () => createVideoSession(document),
        isVideoSessionActive: () => isVideoSessionActive(document),
        getVideoSession: () => getVideoSession<ReturnType<typeof createVideoSession>>(),
        resolveActiveSelection: () => selectionTracker.resolveActiveSelection(),
        restoreSelectionFromSnapshot: (snapshot) =>
          selectionTracker.restoreSelectionFromSnapshot(snapshot),
        getLastSelectionSnapshot: () => runtimeState.getLastSelectionSnapshot(),
        clearLastSelectionSnapshot: () => runtimeState.setLastSelectionSnapshot(null)
      })
  });
  runtime.start();
  window.addEventListener('pagehide', () => runtime.stop(), { passive: true });
}

import type { ClipPromptGateway } from '../clipper/application/clipPromptGateway';
import { DEFAULT_FRAGMENT_CONFIG } from '../clipper/services/fragmentConfig';
import { ADD_HIGHLIGHT_EVENT } from './constants';
import { handleReaderKeydown, isNodeInsideReaderUi } from './sessionDom';
import { ReaderSessionState, resolveReadingConfig } from './sessionState';
import type { ReaderBootstrapHighlight } from './types';
import type { ExternalHighlightPayload } from './types';
import type { ReaderSelectionPayload } from './services/selectionController';
import type { ReaderHighlightManager, ReaderHighlightRecord } from './services/highlightManager';
import type { ReaderPanelCoordinator } from './panelCoordinator';
import type { ReaderSelectionController } from './services/selectionController';
import type { ReaderEnvironmentController } from './environmentController';
import type { ReaderSessionLifecycle } from './sessionLifecycle';
import type { ReadingSessionOptions } from '../../shared/types/options';
import {
  clearReaderSession,
  isReaderSessionActive,
  registerReaderSession
} from '../runtime/contentSessionRegistry';
import { clearHighlightThemeState } from '../shared/highlightThemeState';
import type { ReaderSessionDependencies as FullReaderSessionDependencies } from './sessionTypes';
import {
  addReaderHighlightFromRange,
  cancelReaderSession,
  finishReaderSession,
  focusReaderHighlight,
  handleReaderSessionMouseUp,
  handleReaderSessionSelection,
  ingestExternalReaderHighlight,
  removeReaderHighlight,
  submitReaderHighlightEdit
} from './sessionOperations';

export type { ReaderSessionDependencies } from './sessionTypes';

export class ReaderSession {
  private readonly state = new ReaderSessionState();
  private readonly dependencies: FullReaderSessionDependencies;
  private readonly highlightManager: ReaderHighlightManager;
  private readonly panelCoordinator: ReaderPanelCoordinator;
  private readonly selectionController: ReaderSelectionController;
  private readonly environment: ReaderEnvironmentController;
  private readonly lifecycle: ReaderSessionLifecycle;

  private get operationContext() {
    return {
      session: this,
      doc: this.doc,
      url: this.url,
      clipPrompt: this.clipPrompt,
      state: this.state,
      highlightManager: this.highlightManager,
      panelCoordinator: this.panelCoordinator,
      lifecycle: this.lifecycle,
      dependencies: this.dependencies
    };
  }

  constructor(
    private readonly doc: Document,
    private readonly url: string,
    private readonly clipPrompt: ClipPromptGateway,
    dependencies: FullReaderSessionDependencies
  ) {
    this.dependencies = dependencies;
    this.highlightManager = this.dependencies.createHighlightManager(this.doc);
    this.panelCoordinator = this.dependencies.createPanelCoordinator({
      viewFactory: this.dependencies.viewFactory,
      callbacks: {
        onFinish: () => this.finish(),
        onCancel: () => this.cancel(),
        onDeleteHighlight: (id) => this.removeHighlightById(id),
        onSubmitHighlightEdit: (id, comment) => this.submitHighlightEdit(id, comment),
        onFocusHighlight: (id) => this.focusHighlight(id)
      },
      reconstructText: (highlight) => this.highlightManager.reconstructText(highlight)
    });
    this.selectionController = this.dependencies.createSelectionController({
      doc: this.doc,
      fragmentConfig: DEFAULT_FRAGMENT_CONFIG,
      canHandleSelection: () => !this.state.handlingSelection && !this.state.exporting,
      isNodeInsideUi: (node) =>
        isNodeInsideReaderUi(node, this.panelCoordinator.getElement(), this.doc),
      onSelectionReady: (payload) => {
        void this.handleSelection(payload);
      }
    });
    this.environment = this.dependencies.createEnvironmentController(
      {
        doc: this.doc,
        storage: this.dependencies.storage,
        optionsRepository: this.dependencies.optionsRepository
      },
      {
        onMessagesUpdate: (messages) => {
          this.state.messages = messages;
          this.panelCoordinator.updateMessages(messages, this.state.highlights);
        },
        onFragmentConfigUpdate: (config) => {
          this.selectionController.updateFragmentConfig(config);
        }
      }
    );
    this.lifecycle = this.dependencies.createLifecycle(
      {
        doc: this.doc,
        selectionController: this.selectionController,
        panelCoordinator: this.panelCoordinator,
        environment: this.environment,
        externalHighlightEvent: ADD_HIGHLIGHT_EVENT
      },
      {
        onSelection: (_payload) => {
          // Selection flow is already owned by the selection controller wiring.
        },
        onExternalHighlight: (payload) => this.ingestExternalHighlightPayload(payload),
        onKeydown: (event) => {
          handleReaderKeydown(event, {
            isPanelEditing: () => this.panelCoordinator.isEditing(),
            onCancel: () => this.cancel(),
            onFinish: () => this.finish()
          });
        }
      }
    );
  }

  async initialize(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): Promise<void> {
    await this.start(initialHighlights);
  }

  destroy(): void {
    this.cancel();
  }

  __setTestHighlights(
    records: Array<{
      id: string;
      selectedHtml: string;
      selectedText: string;
      comment: string;
      fragmentUrl: string;
      wrapper: HTMLElement;
    }>
  ): void {
    this.state.highlights = records.map((record) => ({
      id: record.id,
      selectedHtml: record.selectedHtml,
      selectedText: record.selectedText,
      comment: record.comment,
      fragmentUrl: record.fragmentUrl,
      wrapper: record.wrapper,
      wrapperSegments: [record.wrapper],
      createdAt: Date.now()
    }));
    this.syncHighlightsUi();
  }

  get __testHighlights(): Array<{
    id: string;
    selectedHtml: string;
    selectedText: string;
    comment: string;
    fragmentUrl: string;
    wrapper: HTMLElement;
  }> {
    return this.state.highlights;
  }

  async start(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): Promise<void> {
    if (isReaderSessionActive(this.doc)) {
      return;
    }

    registerReaderSession(this, this.doc);

    try {
      await this.lifecycle.start();
      this.applyReadingConfig(await this.loadReadingConfig());
      this.watchReadingConfig();
      this.bootstrapHighlights(initialHighlights);
      this.panelCoordinator.refreshHint(this.state.highlights.length);
    } catch (error) {
      clearReaderSession(this, this.doc);
      throw error;
    }
  }

  private bootstrapHighlights(
    initialHighlights?: ReaderBootstrapHighlight | ReaderBootstrapHighlight[]
  ): void {
    const bootHighlights = initialHighlights
      ? Array.isArray(initialHighlights)
        ? initialHighlights
        : [initialHighlights]
      : [];

    for (const highlight of bootHighlights) {
      try {
        this.addHighlightFromRange(
          highlight.range,
          highlight.selectedHtml,
          highlight.selectedText,
          highlight.comment
        );
      } catch (error) {
        console.error('[ReaderSession] Failed to add initial highlight:', error);
      }
    }
  }

  private async loadReadingConfig(): Promise<ReadingSessionOptions> {
    try {
      return resolveReadingConfig(await this.dependencies.readerRepository.getReadingConfig());
    } catch (error) {
      console.warn('[ReaderSession] Failed to load reading config, using defaults:', error);
      return resolveReadingConfig();
    }
  }

  private watchReadingConfig(): void {
    this.state.stopReadingConfigWatcher?.();
    this.state.stopReadingConfigWatcher = this.dependencies.readerRepository.onConfigChange(
      (config) => {
        this.applyReadingConfig(resolveReadingConfig(config));
      }
    );
  }

  private applyReadingConfig(config: ReturnType<typeof resolveReadingConfig>): void {
    this.state.readingConfig = config;
    this.highlightManager.applyTheme(config.highlightTheme);
  }

  private async handleSelection(payload: ReaderSelectionPayload): Promise<void> {
    await handleReaderSessionSelection(this.operationContext, payload);
  }

  private async handleMouseUp(event: MouseEvent): Promise<void> {
    await handleReaderSessionMouseUp(this.operationContext, event);
  }

  private addHighlightFromRange(
    range: Range,
    selectedHtml: string,
    selectedText: string,
    comment: string
  ): void {
    addReaderHighlightFromRange(this.operationContext, range, selectedHtml, selectedText, comment);
  }

  ingestExternalHighlight(
    range: Range,
    selectedHtml: string,
    selectedText: string,
    comment: string
  ): void {
    this.ingestExternalHighlightPayload({ range, selectedHtml, selectedText, comment });
  }

  private ingestExternalHighlightPayload(payload: ExternalHighlightPayload): void {
    ingestExternalReaderHighlight(this.operationContext, payload);
  }

  private syncHighlightsUi(): void {
    this.highlightManager.sortByDocumentOrder(this.state.highlights);
    this.panelCoordinator.updateHighlights(this.state.highlights);
  }

  private async finish(): Promise<void> {
    await finishReaderSession(
      this.operationContext,
      () => this.loadReadingConfig(),
      (config) => this.applyReadingConfig(config)
    );
  }

  private cancel(): void {
    cancelReaderSession(this.operationContext);
  }

  private cleanup(): void {
    this.lifecycle.cleanup();
    this.state.stopReadingConfigWatcher?.();
    this.state.stopReadingConfigWatcher = null;

    for (const highlight of this.state.highlights) {
      this.highlightManager.unwrapHighlight(highlight);
    }
    this.state.highlights = [];

    clearReaderSession(this, this.doc);
    this.state.exporting = false;
    this.state.handlingSelection = false;
    clearHighlightThemeState(this.doc);

    if (this.state.highlightFocusTimeout !== null) {
      this.doc.defaultView?.clearTimeout(this.state.highlightFocusTimeout);
      this.state.highlightFocusTimeout = null;
    }

    this.doc.defaultView?.getSelection()?.removeAllRanges();
  }

  private focusHighlight(id: string): void {
    focusReaderHighlight(this.operationContext, id);
  }

  private removeHighlightById(id: string): void {
    removeReaderHighlight(this.operationContext, id);
  }

  private submitHighlightEdit(id: string, nextComment: string): void {
    submitReaderHighlightEdit(this.operationContext, id, nextComment);
  }

  private findHighlight(id: string): ReaderHighlightRecord | undefined {
    return this.state.highlights.find((highlight) => highlight.id === id);
  }
}

import { getErrorHandler, extractionErrors, normalizeToAppError, type AppError } from '../../shared/errors';
import { shouldTriggerSelectionWithModifiers, syncModifierState } from '../clipper/services/fragmentConfig';
import type { ContentRuntimeState } from './contentRuntimeState';
import type { ContentSelectionTracker, SelectionSnapshot } from './contentSelectionTracker';
import type { MessagePayload, MessagingService } from '../../platform/interfaces/messaging';
import type { ExtractorRegistryApi } from '../extractors/registry';
import { isReaderSessionActive, isVideoSessionActive } from './contentSessionRegistry';

export interface VideoSelectionController {
  handleSelectionClip(
    document: Document,
    url: string,
    selection: Selection
  ): Promise<{ markdown?: string; type?: string } | null>;
  handleVideoSelectionClip(document: Document, url: string, selection: Selection): Promise<void>;
}

export interface InitClipFlowOptions {
  document: Document;
  window: Window;
  messaging: Pick<MessagingService, 'send'>;
  runtimeState: ContentRuntimeState;
  selectionTracker: ContentSelectionTracker;
  selectionController: VideoSelectionController;
  extractorRegistry: ExtractorRegistryApi;
}

export interface ClipFlowHandlers {
  handleClip(): Promise<void>;
  handleAutoSelectionClip(event: MouseEvent): void;
  handleModifierKey(event: KeyboardEvent): void;
  handleWindowBlur(): void;
  handlePrimaryMouseDown(event: MouseEvent): void;
  handleSelectionChange(): void;
  handleSelectStart(event: Event): void;
}

export function initClipFlow(options: InitClipFlowOptions): ClipFlowHandlers {
  const { document, window, messaging, runtimeState, selectionTracker, selectionController, extractorRegistry } = options;

  async function emitClipError(error: AppError): Promise<void> {
    const errorHandler = getErrorHandler();
    await errorHandler.handle(error, { suppressNotifications: true });

    try {
      await messaging.send({ type: 'CLIP_ERROR', error });
    } catch (sendError) {
      const message = sendError instanceof Error ? sendError.message : String(sendError);
      const contextInput: { url: string; type?: string } = { url: location.href };
      const errorType = error.context?.type as string | undefined;
      if (errorType !== undefined) {
        contextInput.type = errorType;
      }
      const dispatchError = extractionErrors.dispatchFailure(message, contextInput);
      const handler = getErrorHandler();
      await handler.handle(dispatchError, { suppressNotifications: true });
    }
  }

  async function handleClip(): Promise<void> {
    const url = location.href;
    const doc = document;
    const clipMode = runtimeState.getClipMode();
    try {
      let result: { markdown?: string; type?: string } | undefined;

      if (clipMode === 'selection') {
        let selectionInfo = selectionTracker.resolveActiveSelection();
        if ((!selectionInfo || selectionInfo.selection.rangeCount === 0 || selectionInfo.selection.isCollapsed) && runtimeState.getLastSelectionSnapshot()) {
          selectionInfo = selectionTracker.restoreSelectionFromSnapshot(runtimeState.getLastSelectionSnapshot());
        }

        const selection = selectionInfo?.selection ?? null;

        if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
          throw extractionErrors.noSelection({
            url,
            type: 'selection',
            selectionLength: selection ? selection.toString().length : 0
          });
        }

        if (isVideoSessionActive(doc)) {
          await selectionController.handleVideoSelectionClip(doc, url, selection);
          runtimeState.setClipMode('full');
          runtimeState.setLastSelectionSnapshot(null);
          return;
        }

        const clip = await selectionController.handleSelectionClip(doc, url, selection);
        runtimeState.setClipMode('full');
        runtimeState.setLastSelectionSnapshot(null);
        if (!clip) {
          return;
        }
        result = clip;
      } else {
        result = await extractorRegistry.extract({ url, document: doc });
      }

      if (!result || !result.markdown) {
        const noMarkdownContext: { url: string; type?: string } = { url };
        const resultType = result?.type;
        if (resultType !== undefined) {
          noMarkdownContext.type = resultType;
        }
        throw extractionErrors.noMarkdown(noMarkdownContext);
      }

      try {
        await messaging.send({ type: 'CLIP_RESULT', payload: result as MessagePayload });
      } catch (sendError) {
        const message = sendError instanceof Error ? sendError.message : String(sendError);
        const dispatchContext: { url: string; type?: string } = { url };
        const resultType = result?.type;
        if (resultType !== undefined) {
          dispatchContext.type = resultType;
        }
        throw extractionErrors.dispatchFailure(message, dispatchContext);
      }
    } catch (error) {
      const appError = normalizeToAppError(error, {
        code: 'CONTENT_CLIP_FAILURE',
        domain: 'content',
        defaultMessage: 'Clip failed due to an unexpected error.',
        context: { url, mode: clipMode }
      });
      await emitClipError(appError);
    }
  }

  const handleModifierKey = (event: KeyboardEvent): void => {
    syncModifierState(runtimeState.getModifierState(), event);
  };

  const handleWindowBlur = (): void => {
    runtimeState.resetSelectionTracking();
  };

  const handlePrimaryMouseDown = (event: MouseEvent): void => {
    if (event.button !== 0) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    syncModifierState(runtimeState.getModifierState(), event);
    const fragmentClipperConfig = runtimeState.getFragmentClipperConfig();
    if (!fragmentClipperConfig.selectionModifierEnabled) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    runtimeState.setSelectionModifierActive(
      shouldTriggerSelectionWithModifiers(fragmentClipperConfig, runtimeState.getModifierState())
    );
  };

  const handleAutoSelectionClip = (event: MouseEvent): void => {
    if (event.button !== 0) {
      return;
    }
    if (isReaderSessionActive(document)) {
      return;
    }
    syncModifierState(runtimeState.getModifierState(), event);
    const fragmentClipperConfig = runtimeState.getFragmentClipperConfig();
    const modifierRequired = fragmentClipperConfig.selectionModifierEnabled;
    const modifiersSatisfied = runtimeState.isSelectionModifierActive()
      || shouldTriggerSelectionWithModifiers(fragmentClipperConfig, runtimeState.getModifierState());
    if (modifierRequired && !modifiersSatisfied) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }

    const selectionInfo = selectionTracker.resolveActiveSelection();
    if (!selectionInfo) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }

    const selection = selectionInfo.selection;
    if (!selection || selection.rangeCount === 0 || selection.isCollapsed) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    if (!selection.toString().trim()) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    if (selectionTracker.isSelectionInsideUi(selection) || selectionTracker.isSelectionEditable(selection)) {
      runtimeState.setSelectionModifierActive(false);
      return;
    }
    if (runtimeState.getAutoSelectionInFlight()) {
      return;
    }

    runtimeState.setAutoSelectionInFlight(true);
    runtimeState.setClipMode('selection');
    void handleClip().finally(() => {
      runtimeState.setAutoSelectionInFlight(false);
      runtimeState.setSelectionModifierActive(false);
    });
  };

  const handleSelectionChange = (): void => {
    selectionTracker.handleSelectionChange();
  };

  const handleSelectStart = (_event: Event): void => {
    selectionTracker.handleSelectStart();
  };

  return {
    handleClip,
    handleAutoSelectionClip,
    handleModifierKey,
    handleWindowBlur,
    handlePrimaryMouseDown,
    handleSelectionChange,
    handleSelectStart
  };
}

type ContentSessionRegistryState = {
  readerSession: unknown | null;
  videoSession: unknown | null;
};

const state: ContentSessionRegistryState = {
  readerSession: null,
  videoSession: null
};

function getRoot(doc: Document = document): HTMLElement {
  return doc.documentElement;
}

function setDatasetFlag(root: HTMLElement, key: string, active: boolean): void {
  if (active) {
    root.dataset[key] = 'true';
    return;
  }
  delete root.dataset[key];
}

export function markContentRuntimeInitialized(doc: Document = document): boolean {
  const root = getRoot(doc);
  if (root.dataset.aiobContentRuntime === 'true') {
    return false;
  }
  root.dataset.aiobContentRuntime = 'true';
  return true;
}

export function registerReaderSession(session: unknown, doc: Document = document): void {
  state.readerSession = session;
  setDatasetFlag(getRoot(doc), 'aiobReaderActive', true);
}

export function clearReaderSession(session?: unknown, doc: Document = document): void {
  if (session !== undefined && state.readerSession !== session) {
    return;
  }
  state.readerSession = null;
  setDatasetFlag(getRoot(doc), 'aiobReaderActive', false);
}

export function getReaderSession<T>(): T | null {
  return (state.readerSession as T | null) ?? null;
}

export function isReaderSessionActive(doc: Document = document): boolean {
  return state.readerSession !== null || getRoot(doc).dataset.aiobReaderActive === 'true';
}

export function registerVideoSession(session: unknown, doc: Document = document): void {
  state.videoSession = session;
  setDatasetFlag(getRoot(doc), 'aiobVideoActive', true);
}

export function clearVideoSession(session?: unknown, doc: Document = document): void {
  if (session !== undefined && state.videoSession !== session) {
    return;
  }
  state.videoSession = null;
  setDatasetFlag(getRoot(doc), 'aiobVideoActive', false);
}

export function getVideoSession<T>(): T | null {
  return (state.videoSession as T | null) ?? null;
}

export function isVideoSessionActive(doc: Document = document): boolean {
  return state.videoSession !== null || getRoot(doc).dataset.aiobVideoActive === 'true';
}

export function __resetContentSessionRegistryForTests(doc: Document = document): void {
  state.readerSession = null;
  state.videoSession = null;
  const root = getRoot(doc);
  delete root.dataset.aiobContentRuntime;
  delete root.dataset.aiobReaderActive;
  delete root.dataset.aiobVideoActive;
}

export interface DomEventHandlers {
  handleModifierKey(event: KeyboardEvent): void;
  handleWindowBlur(): void;
  handlePrimaryMouseDown(event: MouseEvent): void;
  handleAutoSelectionClip(event: MouseEvent): void;
  handleSelectionChange(): void;
  handleSelectStart(event: Event): void;
}

export interface WireDomEventsOptions {
  document: Document;
  window: Window;
  handlers: DomEventHandlers;
}

export interface DomEventsDisposer {
  dispose(): void;
}

export function wireDomEvents(options: WireDomEventsOptions): DomEventsDisposer {
  const { document, window, handlers } = options;

  let attached = false;

  const keydown = handlers.handleModifierKey;
  const keyup = handlers.handleModifierKey;
  const blur = handlers.handleWindowBlur;
  const mousedown = handlers.handlePrimaryMouseDown;
  const mouseup = handlers.handleAutoSelectionClip;
  const selectionchange = handlers.handleSelectionChange;
  const selectstart = handlers.handleSelectStart as EventListener;

  if (!attached) {
    document.addEventListener('keydown', keydown, true);
    document.addEventListener('keyup', keyup, true);
    window.addEventListener('blur', blur, true);
    document.addEventListener('mousedown', mousedown, true);
    document.addEventListener('mouseup', mouseup, true);
    document.addEventListener('selectionchange', selectionchange, true);
    document.addEventListener('selectstart', selectstart, true);
    attached = true;
  }

  return {
    dispose: () => {
      if (!attached) return;
      document.removeEventListener('keydown', keydown, true);
      document.removeEventListener('keyup', keyup, true);
      window.removeEventListener('blur', blur, true);
      document.removeEventListener('mousedown', mousedown, true);
      document.removeEventListener('mouseup', mouseup, true);
      document.removeEventListener('selectionchange', selectionchange, true);
      document.removeEventListener('selectstart', selectstart, true);
      attached = false;
    }
  };
}

import type { LikeToastVariant, SupportPromptMessages, ToastVariant } from './types';
import { panelStyleSheetManager } from '../../shared/panels/styleSheetManager';

const TOAST_AUTO_DISMISS_MS = 5000;

interface SupportPromptToastControllerOptions {
  doc: Document;
  resolveReviewUrl: () => string;
  onReviewLinkClick: (variant?: LikeToastVariant) => Promise<void>;
  onReviewAcknowledgedClick: (variant?: LikeToastVariant) => Promise<void>;
  onDislikeRedditClick: () => void;
  onDislikeQrClick: () => void;
  onLikeToastShown: (variant: LikeToastVariant) => void;
  onDislikeToastShown: () => void;
}

export class SupportPromptToastController {
  private activeHost: HTMLDivElement | null = null;
  private activeToast: HTMLDivElement | null = null;
  private activeToastVariant: ToastVariant | null = null;
  private toastTimer: number | null = null;

  private readonly handleToastPointerDown = (event: PointerEvent): void => {
    if (!this.activeToast) {
      return;
    }
    const target = event.target;
    if (target instanceof Node && this.activeHost?.contains(target)) {
      return;
    }
    this.dismissToast();
  };

  constructor(private readonly options: SupportPromptToastControllerOptions) {}

  destroy(): void {
    this.dismissToast(true);
  }

  showLikeToast(messages: SupportPromptMessages, variant: LikeToastVariant): void {
    const toast = this.createBaseToast('like');
    toast.dataset.variant = variant;

    const messageLine = this.options.doc.createElement('div');
    messageLine.dataset.role = 'like-toast-message';
    messageLine.className = 'm-0 text-[13px] font-semibold';
    messageLine.textContent = messages.likeThankYou;
    toast.appendChild(messageLine);

    if (variant !== 'acknowledged') {
      const links = this.options.doc.createElement('div');
      links.className = 'mt-2 flex flex-col gap-1.5';

      if (variant === 'returning') {
        const acknowledgedLink = this.options.doc.createElement('button');
        acknowledgedLink.type = 'button';
        acknowledgedLink.dataset.role = 'review-acknowledged-btn';
        acknowledgedLink.className = 'text-[12px] underline text-left';
        acknowledgedLink.textContent = messages.reviewAcknowledgedLabel;
        acknowledgedLink.addEventListener('click', (event) => {
          event.preventDefault();
          void this.options.onReviewAcknowledgedClick(variant);
        });
        links.appendChild(acknowledgedLink);
      }

      const reviewLink = this.options.doc.createElement('button');
      reviewLink.type = 'button';
      reviewLink.dataset.role = 'review-link-btn';
      reviewLink.className = 'text-[12px] underline text-left';
      reviewLink.textContent = messages.reviewLinkLabel;
      reviewLink.addEventListener('click', (event) => {
        event.preventDefault();
        void this.options.onReviewLinkClick(variant);
      });
      links.appendChild(reviewLink);
      toast.appendChild(links);
    }

    this.showToast(toast, variant);
    this.options.onLikeToastShown(variant);
  }

  showDislikeToast(messages: SupportPromptMessages): void {
    const toast = this.createBaseToast('dislike');

    const title = this.options.doc.createElement('div');
    title.dataset.role = 'dislike-toast-title';
    title.className = 'm-0 text-[13px] font-semibold';
    title.textContent = messages.dislikeToastTitle;
    toast.appendChild(title);

    const links = this.options.doc.createElement('div');
    links.className = 'mt-2 flex flex-col gap-1.5';

    const redditLink = this.options.doc.createElement('a');
    redditLink.dataset.role = 'reddit-link';
    redditLink.className = 'text-[12px] underline';
    redditLink.href = 'https://www.reddit.com/r/ObsidianMD/comments/1oahhds/i_made_a_browser_extension_for_a_better/?utm_source=share&utm_medium=web3x&utm_name=web3xcss&utm_term=1&utm_content=share_button';
    redditLink.target = '_blank';
    redditLink.rel = 'noopener noreferrer';
    redditLink.textContent = messages.dislikeRedditLinkLabel;
    redditLink.addEventListener('click', () => {
      this.options.onDislikeRedditClick();
    });
    links.appendChild(redditLink);

    const qrLink = this.options.doc.createElement('button');
    qrLink.type = 'button';
    qrLink.dataset.role = 'qr-toggle-btn';
    qrLink.className = 'text-[12px] underline text-left';
    qrLink.textContent = messages.dislikeQrLinkLabel;

    const qrContainer = this.options.doc.createElement('div');
    qrContainer.dataset.role = 'qr-container';
    qrContainer.className = 'mt-2 rounded-[10px] bg-[rgba(42,46,74,0.65)] p-[10px] text-center';
    qrContainer.hidden = true;

    const qrPlaceholder = this.options.doc.createElement('div');
    qrPlaceholder.dataset.role = 'qr-placeholder';
    qrPlaceholder.className = 'text-[11px] text-[rgba(200,205,255,0.7)]';
    qrPlaceholder.textContent = messages.dislikeQrPlaceholder ?? '二维码即将提供';
    qrContainer.appendChild(qrPlaceholder);

    qrLink.addEventListener('click', (event) => {
      event.preventDefault();
      qrContainer.hidden = !qrContainer.hidden;
      this.options.onDislikeQrClick();
    });

    links.appendChild(qrLink);
    toast.append(links, qrContainer);

    this.showToast(toast, 'dislike');
    this.options.onDislikeToastShown();
  }

  private createBaseToast(kind: 'like' | 'dislike'): HTMLDivElement {
    this.dismissToast(true);
    const host = this.options.doc.createElement('div');
    host.id = 'aiob-support-toast-host';
    const shadow = host.attachShadow({ mode: 'open' });
    panelStyleSheetManager.initialize();
    panelStyleSheetManager.applyReaderStyles(shadow);

    const toast = this.options.doc.createElement('div');
    toast.id = 'aiob-support-toast';
    toast.dataset.kind = kind;
    toast.className = 'fixed right-6 bottom-6 z-[2147483647] min-w-[220px] max-w-[260px] rounded-[14px] p-[14px_16px] bg-[#171b30]/95 border border-[#7c5cff]/35 shadow-[0_10px_28px_rgba(17,22,45,0.45)] text-[#eef0ff] font-sans opacity-0 pointer-events-none translate-y-2 transition-all duration-200 ease-out backdrop-blur-[14px]';
    shadow.appendChild(toast);
    this.activeHost = host;
    return toast;
  }

  private showToast(toast: HTMLDivElement, variant: ToastVariant): void {
    if (!this.activeHost) {
      return;
    }
    this.options.doc.body.appendChild(this.activeHost);
    this.activeToast = toast;
    this.activeToastVariant = variant;

    requestAnimationFrame(() => {
      toast.classList.remove('opacity-0', 'pointer-events-none', 'translate-y-2');
      toast.classList.add('opacity-100', 'pointer-events-auto', 'translate-y-0');
    });

    if (this.toastTimer !== null) {
      window.clearTimeout(this.toastTimer);
    }
    this.toastTimer = window.setTimeout(() => this.dismissToast(), TOAST_AUTO_DISMISS_MS);
    this.options.doc.addEventListener('pointerdown', this.handleToastPointerDown, true);
  }

  dismissToast(immediate = false): void {
    if (!this.activeToast) {
      return;
    }
    if (this.toastTimer !== null) {
      window.clearTimeout(this.toastTimer);
      this.toastTimer = null;
    }
    this.options.doc.removeEventListener('pointerdown', this.handleToastPointerDown, true);

    const toast = this.activeToast;
    const remove = () => {
      toast.removeEventListener('transitionend', remove);
      this.activeHost?.remove();
      if (this.activeToast === toast) {
        this.activeHost = null;
        this.activeToast = null;
        this.activeToastVariant = null;
      }
    };

    if (immediate) {
      remove();
      return;
    }

    toast.addEventListener('transitionend', remove);
    toast.classList.remove('opacity-100', 'pointer-events-auto', 'translate-y-0');
    toast.classList.add('opacity-0', 'pointer-events-none', 'translate-y-2');
  }
}

import type { VideoPanelCallbacks, VideoPanelTexts } from './application/videoPanelModel';
import type { VideoSessionViewFactory } from './application/videoSessionView';
import { VideoPanelPresenter } from './videoPanelPresenter';
import type { VideoHintState } from './videoHintManager';
import { VideoHintManager } from './videoHintManager';
import { buildVideoHintContext, partitionVideoPanelCaptures, type VideoSessionState } from './sessionState';
import type { VideoFragmentCapture } from './types';

export interface VideoSessionDomListenerHandlers {
  onMouseDown(event: MouseEvent): void;
  onKeyDown(event: KeyboardEvent): void;
  onKeyUp(event: KeyboardEvent): void;
  onWindowBlur(): void;
}

export class VideoSessionDomController {
  private panelPresenter: VideoPanelPresenter | null = null;
  private panel = null as ReturnType<VideoSessionViewFactory['createView']> | null;
  private listeners: VideoSessionDomListenerHandlers | null = null;

  constructor(
    private readonly doc: Document,
    private readonly viewFactory: VideoSessionViewFactory,
    private readonly hintManager: VideoHintManager
  ) {}

  async waitForDocumentReady(): Promise<void> {
    if (this.doc.body) {
      return;
    }

    if (this.doc.readyState === 'loading') {
      await new Promise<void>((resolve) => {
        this.doc.addEventListener('DOMContentLoaded', () => resolve(), { once: true });
      });
      if (this.doc.body) {
        return;
      }
    }

    if (typeof MutationObserver === 'undefined') {
      if (this.doc.body) {
        return;
      }
      await new Promise<void>((resolve) => {
        const view = this.doc.defaultView ?? window;
        const interval = view.setInterval(() => {
          if (this.doc.body) {
            view.clearInterval(interval);
            resolve();
          }
        }, 16);
      });
      return;
    }

    await new Promise<void>((resolve) => {
      const target = this.doc.documentElement ?? this.doc;
      const observer = new MutationObserver(() => {
        if (this.doc.body) {
          observer.disconnect();
          resolve();
        }
      });
      try {
        observer.observe(target, { childList: true, subtree: target === this.doc.documentElement });
      } catch {
        resolve();
        return;
      }
      if (this.doc.body) {
        observer.disconnect();
        resolve();
      }
    });
  }

  mountPanel(callbacks: VideoPanelCallbacks, texts: VideoPanelTexts): void {
    this.panel = this.viewFactory.createView(callbacks, texts);
    this.panelPresenter = new VideoPanelPresenter(this.panel);
    this.panelPresenter.updateTexts(texts);
    this.panelPresenter.render({ timestamps: [], fragments: [] });
  }

  updateTexts(texts: VideoPanelTexts): void {
    this.panelPresenter?.updateTexts(texts);
  }

  syncPanel(
    state: VideoSessionState,
    getFragmentElement: (capture: VideoFragmentCapture) => HTMLElement | null
  ): number {
    if (!this.panelPresenter) {
      return 0;
    }

    const groups = partitionVideoPanelCaptures(state.captures, getFragmentElement);
    return this.panelPresenter.render(groups);
  }

  applyHint(state: VideoHintState, sessionState: Pick<VideoSessionState, 'videoElement' | 'captures'>): void {
    const { hint } = this.hintManager.apply(state, buildVideoHintContext(sessionState));
    this.panel?.updateHint(hint);
  }

  refreshHint(sessionState: Pick<VideoSessionState, 'videoElement' | 'captures'>): void {
    const { hint } = this.hintManager.refresh(buildVideoHintContext(sessionState));
    this.panel?.updateHint(hint);
  }

  beginEditingCapture(captureId: string, comment: string): void {
    this.panel?.beginEditingCapture(captureId, comment);
  }

  stopEditing(): void {
    this.panel?.stopEditing();
  }

  registerInteractionHandlers(handlers: VideoSessionDomListenerHandlers): void {
    this.listeners = handlers;
    this.doc.addEventListener('mousedown', handlers.onMouseDown, true);
    this.doc.addEventListener('keydown', handlers.onKeyDown, true);
    this.doc.addEventListener('keyup', handlers.onKeyUp, true);
    this.doc.defaultView?.addEventListener('blur', handlers.onWindowBlur, true);
  }

  removeInteractionHandlers(): void {
    if (!this.listeners) {
      return;
    }
    this.doc.removeEventListener('mousedown', this.listeners.onMouseDown, true);
    this.doc.removeEventListener('keydown', this.listeners.onKeyDown, true);
    this.doc.removeEventListener('keyup', this.listeners.onKeyUp, true);
    this.doc.defaultView?.removeEventListener('blur', this.listeners.onWindowBlur, true);
    this.listeners = null;
  }

  destroy(): void {
    this.removeInteractionHandlers();
    this.panel?.destroy();
    this.panel = null;
    this.panelPresenter = null;
  }
}

import type { ReaderHighlightTheme } from '../../shared/types/options';
