        setStatus('VideoSession exported once');
        return { success: true };
      },
      onConfigChange() {
        return () => undefined;
      }
    } as never,
    storage
  } as never);
  await activeVideo.start();
  await (activeVideo as unknown as { handleAddCapture: () => Promise<void> }).handleAddCapture();
  setStatus('VideoSession mounted and one capture added');
}

