Object.assign(globalThis as Record<string, unknown>, {
  __AIIINOB_SENTRY_ENABLED__: true,
  __AIIINOB_SENTRY_DSN__: 'https://public@example.ingest.sentry.io/123456',
  __AIIINOB_SENTRY_ENVIRONMENT__: 'harness',
