import { DEFAULT_LANGUAGE, getLanguageFallbackChain } from './config';
import type { LangCode } from './config';
import type { LocaleDefinition, LocaleStaticMessages } from './localeDefinition';
import en from './locales/en';

export type Language = LangCode;

export type { Messages } from './messages';
export { DEFAULT_LANGUAGE, AVAILABLE_LANGUAGES } from './config';

type LocaleModule = { default: LocaleDefinition };
type LocaleLoader = () => Promise<LocaleDefinition>;
type LocaleCache = Partial<Record<Language, LocaleDefinition>>;

const localeLoaders: Record<Language, LocaleLoader> = {
  en: async () => en,
  'zh-CN': async () => (await import('./locales/zh-CN')).default,
  ja: async () => (await import('./locales/ja')).default,
  de: async () => (await import('./locales/de')).default,
  fr: async () => (await import('./locales/fr')).default,
  'es-ES': async () => (await import('./locales/es-ES')).default,
  'es-419': async () => (await import('./locales/es-419')).default,
  it: async () => (await import('./locales/it')).default,
  ko: async () => (await import('./locales/ko')).default,
  'pt-BR': async () => (await import('./locales/pt-BR')).default,
  ru: async () => (await import('./locales/ru')).default,
  'zh-TW': async () => (await import('./locales/zh-TW')).default,
  'qps-ploc': async () => (await import('./locales/qps-ploc')).default
};

const localeCache: LocaleCache = {
  en
};

const pendingLocaleLoads = new Map<Language, Promise<LocaleDefinition>>();

export const DEFAULT_RUNTIME_MESSAGES = en.runtime;
export const DEFAULT_STATIC_MESSAGES = en.static;

export function getLocaleCodes(): Language[] {
  return Object.keys(localeLoaders) as Language[];
}

export function hasLocaleLoader(language: string): language is Language {
  return Reflect.has(localeLoaders, language);
}

export function getCachedLocaleDefinition(language: Language): LocaleDefinition | null {
  return localeCache[language] ?? null;
}

export async function loadLocaleDefinition(language: Language): Promise<LocaleDefinition> {
  const cached = localeCache[language];
  if (cached) {
    return cached;
  }

  const pending = pendingLocaleLoads.get(language);
  if (pending) {
    return pending;
  }

  const loadPromise = localeLoaders[language]()
    .then((definition) => {
      localeCache[language] = definition;
      pendingLocaleLoads.delete(language);
      return definition;
    })
    .catch((error) => {
      pendingLocaleLoads.delete(language);
      throw error;
    });

  pendingLocaleLoads.set(language, loadPromise);
  return loadPromise;
}

export async function loadLocaleMessages(language: Language) {
  const definition = await loadLocaleDefinition(language);
  return definition.runtime;
}

export async function loadStaticMessages(language: Language): Promise<LocaleStaticMessages> {
  const chain = getLanguageFallbackChain(language);
  for (const code of chain) {
    const definition = await loadLocaleDefinition(code);
    if (definition.static) {
      return definition.static;
    }
  }
  return DEFAULT_STATIC_MESSAGES;
}

export async function getStaticMessages(language: Language): Promise<LocaleStaticMessages> {
  return loadStaticMessages(language);
}

export async function loadMessagesWithFallback(language: string) {
  const chain = getLanguageFallbackChain(language);
  for (const code of chain) {
    if (!hasLocaleLoader(code)) {
      continue;
    }
    return loadLocaleMessages(code);
  }
  return DEFAULT_RUNTIME_MESSAGES;
}

import type { Language, Messages } from './locales';
import { DEFAULT_LANGUAGE, DEFAULT_RUNTIME_MESSAGES } from './locales';
import { getLanguageFallbackChain } from './config';
import { createI18nResource } from './resource';
import type { I18nBinder, I18nBindingAdapter, I18nBindingHandle, I18nResource } from './types';
import { updateDynamicMessages } from './dynamicMessages';

export interface PageI18nControllerDependencies {
  bindingAdapter: I18nBindingAdapter;
  defaultLanguage: Language;
  loadMessages(language: Language): Promise<Messages>;
  getCurrentLanguage(): Promise<Language>;
  setCurrentLanguage?(language: Language): Promise<void>;
}

export interface PageI18nController {
  load(languageOverride?: Language): Promise<void>;
  mount(root: ParentNode): void;
  registerDynamic(registrar: (binder: I18nBinder) => void): void;
  changeLanguage(language: Language): Promise<void>;
  dispose(): void;
  getCurrentResource(): I18nResource | null;
  getBinder(): I18nBinder;
}

function createBinder(bindingAdapter: I18nBindingAdapter): I18nBinder {
  return {
    bindText(element, key) {
      return bindingAdapter.bindText(element, key);
    },
    bindAttr(element, attribute, key) {
      return bindingAdapter.bindAttribute(element, attribute, key);
    },
    bindHtml(element, key) {
      return bindingAdapter.bindHtml(element, key);
    }
  };
}

function ensureResource(resource: I18nResource | null): asserts resource is I18nResource {
  if (!resource) {
    throw new Error('[i18n] PageI18nController: resource not loaded. Call load() before mount/register.');
  }
}

const defaultMessages = DEFAULT_RUNTIME_MESSAGES;

function isMessageKey(value: string | null): value is keyof Messages {
  return typeof value === 'string' && value in defaultMessages;
}

function scanStaticBindings(root: ParentNode, binder: I18nBinder): Array<I18nBindingHandle> {
  const handles: Array<I18nBindingHandle> = [];

  root.querySelectorAll<HTMLElement>('[data-i18n]').forEach(element => {
    const key = element.getAttribute('data-i18n');
    if (isMessageKey(key)) {
      handles.push(binder.bindText(element, key));
    }
  });

  root.querySelectorAll<HTMLElement>('[data-i18n-html]').forEach(element => {
    const key = element.getAttribute('data-i18n-html');
    if (isMessageKey(key)) {
      handles.push(binder.bindHtml(element, key));
    }
  });

  root.querySelectorAll<HTMLElement>('[data-i18n-placeholder]').forEach(element => {
    const key = element.getAttribute('data-i18n-placeholder');
    if (isMessageKey(key)) {
      handles.push(binder.bindAttr(element, 'placeholder', key));
    }
  });

  root.querySelectorAll<HTMLElement>('[data-i18n-title]').forEach(element => {
    const key = element.getAttribute('data-i18n-title');
    if (isMessageKey(key)) {
      handles.push(binder.bindAttr(element, 'title', key));
    }
  });

  return handles;
}

export function createPageI18nController(deps: PageI18nControllerDependencies): PageI18nController {
  const { bindingAdapter, defaultLanguage } = deps;
  const loadMessages = (language: Language) => deps.loadMessages(language);
  const readCurrentLanguage = () => deps.getCurrentLanguage();
  const persistLanguage = deps.setCurrentLanguage
    ? (language: Language) => deps.setCurrentLanguage?.(language)
    : undefined;

  const binder = createBinder(bindingAdapter);
  let currentResource: I18nResource | null = null;
  let staticHandles: Array<I18nBindingHandle> = [];

  const refreshBindings = (): void => {
    if (currentResource) {
      bindingAdapter.refresh(currentResource);
    }
  };

  const loadResource = async (language: Language): Promise<Language> => {
    const chain = getLanguageFallbackChain(language);
    const resolvedLanguage = chain[0] ?? defaultLanguage;
    const resolvedMessages = await loadMessages(resolvedLanguage);
    const fallbackChain: Messages[] = [];

    for (const code of chain) {
      if (code === resolvedLanguage) {
        continue;
      }
      const fallbackMessages = await loadMessages(code);
      if (!fallbackChain.includes(fallbackMessages)) {
        fallbackChain.push(fallbackMessages);
      }
    }

    const defaultMessages = await loadMessages(defaultLanguage);
    if (!fallbackChain.includes(defaultMessages)) {
      fallbackChain.push(defaultMessages);
    }

    const resource = createI18nResource({
      language: resolvedLanguage,
      messages: resolvedMessages,
      fallbackChain
    });
    currentResource = resource;
    refreshBindings();
    return resolvedLanguage;
  };

  return {
    async load(languageOverride) {
      const language = languageOverride ?? await readCurrentLanguage();
      await loadResource(language);
    },
    mount(root) {
      ensureResource(currentResource);
      if (staticHandles.length > 0) {
        staticHandles.forEach(handle => handle.dispose());
        staticHandles = [];
      }
      staticHandles = scanStaticBindings(root, binder);
      refreshBindings();
      // Update dynamic messages after static bindings
      updateDynamicMessages(currentResource.language);
    },
    registerDynamic(registrar) {
      ensureResource(currentResource);
      registrar(binder);
      refreshBindings();
    },
    async changeLanguage(language) {
      ensureResource(currentResource);
      if (language === currentResource.language) {
        return;
      }
      const resolvedLanguage = await loadResource(language);
      if (persistLanguage) {
        await persistLanguage(resolvedLanguage);
      }
      // Update dynamic messages after language change
      updateDynamicMessages(resolvedLanguage);
    },
    dispose() {
      staticHandles.forEach(handle => handle.dispose());
      staticHandles = [];
      bindingAdapter.clear();
      currentResource = null;
    },
    getCurrentResource() {
      return currentResource;
    },
    getBinder() {
      return binder;
    }
  };
}

import { deepClone } from '../options/utils/clone';
import type { CompleteOptions, StoredOptions } from '../shared/types/options';
import type { OptionsRepository } from '../shared/interfaces/optionsRepository';
import type { IOptionsRepository } from '../shared/repositories/IOptionsRepository';
import type { StorageService } from '../platform/interfaces/storage';
import { ReactiveStore } from '../shared/state/ReactiveStore';

/**
 * Transitional legacy OptionsRepository compatibility implementation.
 *
 * Options UI 主链已统一迁移到 `IOptionsRepository`；这里只保留给
 * content/background 中仍依赖 load/save/snapshot/subscribe 语义的旧链路。
 * 该实现不再定义 normalize / merge 主链职责，相关行为统一留在
 * `ChromeOptionsRepository` + `optionsStore`。
 *
 * 退役路径：
 * 1. content/background 不再依赖 legacy OptionsRepository。
 * 2. PlatformServices 停止暴露 optionsRepository bridge。
 * 3. 删除该兼容实现与旧工厂别名。
 */
export class ChromeSyncOptionsRepository implements OptionsRepository {
  private readonly store = new ReactiveStore<StoredOptions>();
  private syncPromise: Promise<boolean> | null = null;
  private isSynced = false;
  private storageWatcher: (() => void) | null = null;

  constructor(private readonly storage: StorageService) {}

  private ensureClone(value: StoredOptions | CompleteOptions | undefined | null): StoredOptions | undefined {
    if (!value) {
      return undefined;
    }
    return deepClone(value) as StoredOptions;
  }

  private async ensureSynced(): Promise<void> {
    if (this.isSynced) {
      return;
    }
    if (this.syncPromise === null) {
      this.syncPromise = this.initializeSync();
    }
    await this.syncPromise;
  }

  private async initializeSync(): Promise<boolean> {
    try {
      const storedValue = await this.storage.sync.get<StoredOptions>('options');
      const initialValue = storedValue ? deepClone(storedValue) : undefined;

      if (initialValue) {
        this.store.set(initialValue);
      }

      this.storageWatcher = this.storage.sync.watchKey<StoredOptions>('options', (value) => {
        const mapped = value ? deepClone(value) : undefined;
        this.store.set(mapped);
      });

      this.isSynced = true;
      return true;
    } catch (error) {
      console.warn('[ChromeSyncOptionsRepository] Failed to sync with storage', error);
      this.isSynced = false;
      return false;
    } finally {
      this.syncPromise = null;
    }
  }

  async load(): Promise<StoredOptions> {
    await this.ensureSynced();
    const freshValue = await this.storage.sync.get<StoredOptions>('options');
    const hasValue = Boolean(freshValue);
    const latest = hasValue ? deepClone(freshValue) : ({} as StoredOptions);
    this.store.setSilent(hasValue ? latest : undefined);
    return deepClone(latest) as StoredOptions;
  }

  async save(options: StoredOptions | CompleteOptions): Promise<void> {
    await this.ensureSynced();
    const normalized = this.ensureClone(options) ?? ({} as StoredOptions);
    await this.storage.sync.set('options', normalized);
    this.store.set(normalized);
  }

  snapshot(): StoredOptions | null {
    const current = this.store.get();
    return current ? deepClone(current) : null;
  }

  subscribe(listener: (options: StoredOptions | undefined) => void): () => void {
    return this.store.subscribe((value) => {
      listener(value ? deepClone(value) : undefined);
    });
  }

  reset(): void {
    if (this.storageWatcher) {
      this.storageWatcher();
      this.storageWatcher = null;
    }
    this.store.set(undefined);
    this.isSynced = false;
    this.syncPromise = null;
  }
}

export class LegacyOptionsRepositoryAdapter implements OptionsRepository {
  private readonly store = new ReactiveStore<StoredOptions>();
  private unsubscribe: (() => void) | null = null;
  private pendingLoad: Promise<StoredOptions> | null = null;

  constructor(private readonly repository: IOptionsRepository) {}

  private ensureClone(value: StoredOptions | CompleteOptions | null | undefined): StoredOptions | undefined {
    if (!value) {
      return undefined;
    }

    return deepClone(value) as StoredOptions;
  }

  private ensureSubscription(): void {
    if (this.unsubscribe) {
      return;
    }

    this.unsubscribe = this.repository.onChange((options) => {
      this.store.set(this.ensureClone(options));
    });
  }

  async load(): Promise<StoredOptions> {
    this.ensureSubscription();

    if (this.pendingLoad === null) {
      this.pendingLoad = this.repository
        .get()
        .then((options) => {
          const cloned = this.ensureClone(options) ?? ({} as StoredOptions);
          this.store.setSilent(cloned);
          return deepClone(cloned) as StoredOptions;
        })
        .finally(() => {
          this.pendingLoad = null;
        });
    }

    return this.pendingLoad;
  }

  async save(options: StoredOptions | CompleteOptions): Promise<void> {
    this.ensureSubscription();
    const cloned = this.ensureClone(options) ?? ({} as StoredOptions);
    await this.repository.set(cloned as Partial<CompleteOptions>);
    this.store.set(cloned);
  }

  snapshot(): StoredOptions | null {
    const current = this.store.get();
    return current ? deepClone(current) : null;
  }

  subscribe(listener: (options: StoredOptions | undefined) => void): () => void {
    this.ensureSubscription();

    return this.store.subscribe((value) => {
      listener(value ? deepClone(value) : undefined);
    });
  }

  reset(): void {
    this.unsubscribe?.();
    this.unsubscribe = null;
    this.pendingLoad = null;
    this.store.set(undefined);
  }
}

export function adaptOptionsRepository(repository: IOptionsRepository): OptionsRepository {
  return new LegacyOptionsRepositoryAdapter(repository);
}

export function createCompatibilityOptionsRepository(storage: StorageService): OptionsRepository {
  return new ChromeSyncOptionsRepository(storage);
}

