import { OptionsApp, type OptionsAppUIConfig } from '../components/layout/OptionsApp';
import { createOptionsStateManager } from '../state/StateManager';
import { defaultOptionsState, type OptionsState } from '../state/types';
import {
  DEFAULT_USAGE_STATS,
  USAGE_STATS_STORAGE_KEY,
  normalizeUsageStats
} from '../../shared/constants';
import { getOptionsMessages } from './i18nContext';
import { getCurrentLanguage } from '../../i18n';
import type { UsageStats } from '../../shared/types/usage';
import type { StoredOptions } from '../../shared/types/options';
import { optionsStore } from '../state/optionsStore';
import { getGlobalStateManager } from '../../shared/state';
import type { FormSectionRegistry } from '../components/formSections/formSectionManager';

interface ShellWindow extends Window {
  aiobUsageStats?: UsageStats & { total?: number };
}

export interface MountedOptionsShell {
  cleanup: () => void;
  stateManager: ReturnType<typeof createOptionsStateManager>;
  mountSection: (sectionId: string, options?: { activate?: boolean }) => Promise<void>;
  navigateTo: (sectionId: string) => Promise<void>;
  isSectionMounted: (sectionId: string) => boolean;
  preloadSections: (sectionIds: string[]) => Promise<void>;
  configureUI: (config: OptionsAppUIConfig) => void;
  initialSection: string;
  mountAllSections: () => Promise<void>;
  getMountedSection: (sectionId: string) => unknown | null;
}

export async function mountOptionsShell(
  formRegistry: FormSectionRegistry
): Promise<MountedOptionsShell> {
  if (typeof document === 'undefined') {
    throw new Error('[OptionsShell] document is unavailable during shell mount.');
  }

  const container = document.getElementById('optionsShellRoot');
  if (!container) {
    throw new Error('[OptionsShell] Required #optionsShellRoot container is missing.');
  }

  const messages = await getOptionsMessages();
  const language = await getCurrentLanguage();
  const usage = getInitialUsageStats();
  const stateManager = createOptionsStateManager(buildInitialState(language, usage));
  const initialSection = resolveInitialSection();

  const app = new OptionsApp(container);
  app.setMessages(messages);
  app.render({
    stateManager,
    initialSection,
    formRegistry
  });

  try {
    await app.mountSection(initialSection, true);
  } catch (error) {
    console.error('[OptionsShell] 首屏 Section 挂载失败:', error);
  }

  container.removeAttribute('hidden');
  container.classList.add('is-shell-mounted');
  document.body.classList.add('aobx-shell-active');

  const cleanupHandlers: Array<() => void> = [];
  cleanupHandlers.push(...(await bindOptionsState(stateManager)));
  cleanupHandlers.push(...(await bindUsageState(stateManager)));
  let disposed = false;

  const cleanup = (): void => {
    disposed = true;
    try {
      app.destroy();
    } catch (error) {
      console.error('[OptionsShell] 卸载 UI shell 时出错:', error);
    }

    cleanupHandlers.forEach((dispose) => {
      try {
        dispose();
      } catch (error) {
        console.error('[OptionsShell] 清理监听器时出错:', error);
      }
    });

    container.replaceChildren();
    container.setAttribute('hidden', 'hidden');
    container.classList.remove('is-shell-mounted');
    document.body.classList.remove('aobx-shell-active');
  };

  const collectSectionIds = (): string[] => {
    const ids: string[] = [];
    app.forEachSection((sectionId) => {
      ids.push(sectionId);
    });
    return ids;
  };

  const mountAllSections = async (): Promise<void> => {
    if (disposed) {
      return;
    }
    const sectionIds = collectSectionIds();
    for (const sectionId of sectionIds) {
      if (disposed) {
        return;
      }
      if (sectionId === initialSection && app.getMountedSection(sectionId)) {
        continue;
      }
      try {
        await app.mountSection(sectionId, false);
      } catch (error) {
        console.error('[OptionsShell] 挂载 Section 失败:', sectionId, error);
      }
    }
  };

  return {
    cleanup,
    stateManager,
    initialSection,
    mountAllSections,
    configureUI: (config: OptionsAppUIConfig) => {
      if (disposed) {
        return;
      }
      app.configureUI(config);
    },
    mountSection: async (sectionId: string, options?: { activate?: boolean }) => {
      if (disposed) {
        return;
      }
      await app.mountSection(sectionId, options?.activate ?? false);
    },
    navigateTo: async (sectionId: string) => {
      if (disposed) {
        return;
      }
      await app.navigateTo(sectionId);
    },
    isSectionMounted: (sectionId: string) => {
      if (disposed) {
        return false;
      }
      return app.getMountedSection(sectionId) !== null;
    },
    preloadSections: async (sectionIds: string[]) => {
      if (disposed) {
        return;
      }
      await app.preloadSections(sectionIds);
    },
    getMountedSection: (sectionId: string) => {
      if (disposed) {
        return null;
      }
      return app.getMountedSection(sectionId);
    }
  };
}

function buildInitialState(language: string, usage: UsageStats): OptionsState {
  return {
    ...defaultOptionsState,
    language,
    usage,
    isInitialized: false
  };
}

function getInitialUsageStats(): UsageStats {
  const globalUsage = (window as ShellWindow).aiobUsageStats;
  if (globalUsage) {
    return normalizeUsageStats(globalUsage);
  }
  return { ...DEFAULT_USAGE_STATS };
}

function resolveInitialSection(): string {
  if (typeof window === 'undefined') {
    return 'usage';
  }
  const hash = window.location.hash.replace('#', '');
  if (hash.startsWith('section-')) {
    const sectionId = hash.slice('section-'.length);
    return sectionId.trim() || 'usage';
  }
  return 'usage';
}

async function bindOptionsState(
  stateManager: ReturnType<typeof createOptionsStateManager>
): Promise<Array<() => void>> {
  const disposers: Array<() => void> = [];

  try {
    const stored = await optionsStore.load();
    stateManager.setState({
      options: stored,
      isInitialized: true
    });
  } catch (error) {
    console.warn('[OptionsShell] 加载选项数据失败:', error);
  }

  const unsubscribeStore = optionsStore.subscribe((value: StoredOptions | undefined) => {
    stateManager.setState({
      options: value ?? null,
      isInitialized: true
    });
  });
  disposers.push(unsubscribeStore);

  return disposers;
}

const USAGE_STATE_KEY = 'optionsShell.usageStats';

async function bindUsageState(
  stateManager: ReturnType<typeof createOptionsStateManager>
): Promise<Array<() => void>> {
  const disposers: Array<() => void> = [];
  const globalStateManager = getGlobalStateManager();
  const usageStore = globalStateManager.getStore<UsageStats>(USAGE_STATE_KEY);

  const syncEnabled = await globalStateManager.syncWithStorage(
    USAGE_STATE_KEY,
    USAGE_STATS_STORAGE_KEY
  );
  if (!syncEnabled) {
    stateManager.setState({
      usage: { ...DEFAULT_USAGE_STATS }
    });
  }

  const unsubscribeUsage = usageStore.subscribe((value) => {
    stateManager.setState({
      usage: normalizeUsageStats(value ?? DEFAULT_USAGE_STATS)
    });
  });
  disposers.push(unsubscribeUsage);
  disposers.push(() => {
    globalStateManager.stopSync(USAGE_STATE_KEY);
  });

  return disposers;
}

import { BaseComponent } from '@ui/foundation/lifecycle/BaseComponent';
import { Sidebar, type SidebarConfig, type SidebarFooterLink } from './Sidebar';
import { MainContent } from './MainContent';
import type { NavigationItem } from './Navigation';
import type { OptionsStateManager } from '../../state/StateManager';
import { NavigationController } from './NavigationController';
import { ModalController, type ModalBindingConfig } from '../infrastructure/ModalController';
import type { FormSectionRegistry } from '../formSections/formSectionManager';

export interface OptionsAppConfig {
  stateManager: OptionsStateManager;
  initialSection?: string;
  navigationItems?: NavigationItem[];
  brand?: SidebarConfig['brand'];
  footerLinks?: SidebarConfig['footerLinks'];
  modalBindings?: ModalBindingConfig[];
  formRegistry: FormSectionRegistry;
}

export interface OptionsAppUIConfig {
  modalBindings?: ModalBindingConfig[];
}

/**
 * Root composition component that wires the sidebar and primary content area together.
 */
export class OptionsApp extends BaseComponent<OptionsAppConfig> {
  private stateManager: OptionsStateManager | null = null;
  private sidebar: Sidebar | null = null;
  private content: MainContent | null = null;
  private navigationController: NavigationController | null = null;
  private modalController: ModalController | null = null;
  private formRegistry: FormSectionRegistry | null = null;

  render(config: OptionsAppConfig): HTMLElement {
    this.assertActive();
    this.stateManager = config.stateManager;
    this.formRegistry = config.formRegistry;

    const shell = this.createElement(
      'div',
      'aobx-shell grid grid-cols-1 lg:grid-cols-[252px_minmax(0,1fr)] h-screen min-h-screen overflow-hidden'
    );

    const sidebarHost = this.createElement('div');
    this.sidebar = new Sidebar(sidebarHost);
    if (this.messages) {
      this.sidebar.setMessages(this.messages);
    }
    const sidebarElement = this.sidebar.render(this.buildSidebarConfig(config));
    const sidebarNode = (sidebarElement ??
      sidebarHost.firstElementChild ??
      sidebarHost) as HTMLElement;
    sidebarNode.classList.add(
      'aobx-shell__sidebar',
      'border-b',
      'lg:border-b-0',
      'lg:border-r',
      'border-base-300',
      'bg-base-100',
      'p-6',
      'pb-4',
      'flex',
      'flex-col',
      'gap-5',
      'lg:sticky',
      'lg:top-0',
      'lg:h-screen',
      'lg:max-h-screen',
      'lg:self-start',
      'lg:overflow-y-auto'
    );

    if (!this.stateManager) {
      throw new Error('[OptionsApp] State manager missing during render.');
    }
    const contentHost = this.createElement('div');
    this.content = new MainContent(contentHost);
    if (this.messages) {
      this.content.setMessages(this.messages);
    }
    const contentElement = this.content.render({
      stateManager: this.stateManager,
      ...(config.initialSection !== undefined && { initialSection: config.initialSection }),
      formRegistry: this.formRegistry
    });
    const contentNode = (contentElement ??
      contentHost.firstElementChild ??
      contentHost) as HTMLElement;
    contentNode.classList.add(
      'aobx-shell__content',
      'min-h-screen',
      'h-auto',
      'lg:h-screen',
      'lg:overflow-y-auto',
      'bg-base-200',
      'p-6',
      'px-[clamp(24px,4vw,48px)]'
    );

    shell.append(sidebarNode, contentNode);
    this.container.classList.add(
      'aobx-options-app',
      'min-h-screen',
      'bg-surface',
      'text-text',
      'font-ui',
      'text-md',
      'leading-[1.56]'
    );
    this.container.replaceChildren(shell);

    this.attachNavigationController(shell);
    if (config.modalBindings) {
      this.configureUI({ modalBindings: config.modalBindings });
    }

    return shell;
  }

  destroy(): void {
    this.navigationController?.dispose();
    this.navigationController = null;
    this.modalController?.dispose();
    this.modalController = null;
    this.sidebar?.destroy();
    this.content?.destroy();
    this.sidebar = null;
    this.content = null;
    this.stateManager = null;
    this.formRegistry = null;
    super.destroy();
  }

  async mountSection(sectionId: string, markActive: boolean = false): Promise<void> {
    await this.content?.mountSection(sectionId, markActive);
  }

  async preloadSections(sectionIds: string[]): Promise<void> {
    await this.content?.preloadSections(sectionIds);
  }

  unmountSection(sectionId: string): void {
    this.content?.unmountSection(sectionId);
  }

  async navigateTo(sectionId: string): Promise<void> {
    await this.content?.navigateTo(sectionId);
    this.sidebar?.setActiveNavigation(sectionId);
  }

  getMountedSection(sectionId: string): ReturnType<MainContent['getSectionInstance']> {
    return this.content?.getSectionInstance(sectionId) ?? null;
  }

  forEachSection(callback: Parameters<MainContent['forEachSection']>[0]): void {
    this.content?.forEachSection(callback);
  }

  configureUI(config: OptionsAppUIConfig = {}): void {
    this.assertActive();
    const doc = this.container.ownerDocument ?? (typeof document !== 'undefined' ? document : null);
    const win = doc?.defaultView ?? (typeof window !== 'undefined' ? window : null);

    this.modalController?.dispose();
    this.modalController = null;

    if (doc) {
      this.modalController = new ModalController({
        document: doc,
        window: win,
        ...(config.modalBindings !== undefined && { bindings: config.modalBindings })
      });
    }
  }

  private buildSidebarConfig(config: OptionsAppConfig): SidebarConfig {
    const navigation: SidebarConfig['navigation'] = {
      activeId: config.initialSection ?? 'usage',
      onNavigate: (id: string) => {
        void this.navigateTo(id);
      }
    };

    if (config.navigationItems && config.navigationItems.length > 0) {
      navigation.items = config.navigationItems;
    }

    const brand = config.brand ?? this.buildDefaultBrand();
    return {
      footerLinks: config.footerLinks ?? this.buildDefaultFooterLinks(),
      navigation,
      ...(brand !== undefined && { brand })
    };
  }

  private buildDefaultBrand(): SidebarConfig['brand'] | undefined {
    if (!this.messages) {
      return undefined;
    }

    return {
      title: this.messages.extensionName ?? 'All in Obsidian',
      ...(this.messages.extensionSubtitle !== undefined && {
        subtitle: this.messages.extensionSubtitle
      }),
      ...(this.messages.versionNumber !== undefined && { version: this.messages.versionNumber }),
      logoUrl: '../icons/bannerlogo-128.png'
    };
  }

  private buildDefaultFooterLinks(): SidebarFooterLink[] {
    const links: SidebarFooterLink[] = [];
    if (this.messages?.onboardingLinkText) {
      links.push({
        label: this.messages.onboardingLinkText,
        href: '../onboarding/index.html',
        external: true
      });
    }

    links.push({
      label: this.messages?.footerSupportLink ?? 'Support',
      id: 'supportLink'
    });

    links.push({
      label: this.messages?.footerSuggestionsLink ?? 'Suggestions',
      id: 'suggestionsLink'
    });

    links.push({
      label: this.messages?.footerContactLink ?? 'Contact',
      id: 'contactLink'
    });

    return links;
  }

  private attachNavigationController(root: HTMLElement): void {
    this.navigationController?.dispose();
    const doc = root.ownerDocument ?? (typeof document !== 'undefined' ? document : null);
    const win = doc?.defaultView ?? (typeof window !== 'undefined' ? window : null);
    this.navigationController = new NavigationController({
      root,
      document: doc,
      window: win
    });
  }
}

import { getAvailableLanguages, type Language } from '@i18n';
import type { IOptionsRepository } from '@shared/repositories';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import { UiSelect as DaisySelect } from '@ui/primitives/select';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';
import { changeLanguage } from '../../app/optionsActions';
import { runLanguagePreferenceAction } from '../../app/actions';

interface LanguagePreferenceSnapshot {
  languagePreference?: {
    code?: Language;
  };
}

export class LanguageSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private unsubscribeState: (() => void) | null = null;
  private unsubscribeRepo: (() => void) | null = null;
  private select: HTMLSelectElement | null = null;
  private isProcessing = false;
  private pendingPersistLanguage: Language | null = null;
  private currentLanguage: Language = 'en';

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(context: SectionRenderContext): HTMLElement {
    this.applySectionChrome();
    const header = this.buildHeader();
    const body = this.buildBody();
    this.container.replaceChildren(header, body);

    const state = context.stateManager.getState();
    this.syncFromState(state.language);

    this.unsubscribeState?.();
    this.unsubscribeState = context.stateManager.subscribe((nextState) => {
      this.syncFromState(nextState.language);
    });

    this.subscribeToRepository();

    return this.container;
  }

  override destroy(): void {
    this.unsubscribeState?.();
    this.unsubscribeState = null;
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;
    if (this.select) {
      this.select.removeEventListener('change', this.handleLanguageChange);
    }
    this.select = null;
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    const meta = this.createElement('div', 'text-base-content/60 text-md');
    const selectHost = this.createElement('div');
    const select = new DaisySelect(selectHost).render({
      id: 'languageSelect',
      ariaLabel: this.messages?.languageLabel ?? 'Interface language',
      options: this.getLanguageOptions()
    });
    select.addEventListener('change', this.handleLanguageChange);

    meta.append(selectHost);
    this.select = select;
    return this.buildSectionHeader({
      title: this.messages?.languageSettings ?? 'Language Settings',
      actions: [meta],
      titleClassName: 'm-0 text-2xl font-semibold tracking-tight',
      titleWrapperClassName: 'flex items-center justify-between gap-3 text-base-content flex-wrap'
    });
  }

  private buildBody(): HTMLElement {
    const wrapper = this.createSectionBody();
    const hint = this.createElement(
      'p',
      'text-sm text-base-content/60 bg-base-200 border border-base-300 rounded-md p-3 my-3'
    );
    hint.textContent =
      this.messages?.languageSettings ??
      '修改下拉框后会重新加载界面文字；若翻译未实时更新，请稍候或再次尝试。';
    wrapper.append(hint);
    return wrapper;
  }

  private getLanguageOptions() {
    return getAvailableLanguages().map((language) => ({
      value: language.code,
      label: language.name,
      ...(language.dir === 'rtl' ? { dir: 'rtl' as const } : {}),
      dataAttributes: {
        ...(language.nativeName ? { nativeName: language.nativeName } : {}),
        ...(language.englishName ? { englishName: language.englishName } : {}),
        ...(language.region ? { region: language.region } : {}),
        ...(typeof language.textExpansion === 'number'
          ? { textExpansion: String(language.textExpansion) }
          : {})
      }
    }));
  }

  private syncFromState(language: string): void {
    this.currentLanguage = language as Language;
    if (this.select) {
      this.select.value = language;
    }
  }

  private handleLanguageChange = (event: Event): void => {
    if (this.isProcessing || !this.select) {
      return;
    }

    const nextLanguage = (event.target as HTMLSelectElement).value as Language;
    void this.applyLanguage(nextLanguage, { persist: true });
  };

  private async applyLanguage(language: Language, options: { persist: boolean }): Promise<void> {
    if (this.isProcessing) {
      return;
    }
    this.isProcessing = true;
    if (this.select) {
      this.select.disabled = true;
    }

    try {
      if (options.persist) {
        this.pendingPersistLanguage = language;
      }
      await runLanguagePreferenceAction(
        language,
        {
          changeLanguage,
          optionsRepository: this.optionsRepo
        },
        { persist: options.persist }
      );
      this.currentLanguage = language;
      this.syncFromState(language);
    } catch (error) {
      if (options.persist) {
        this.pendingPersistLanguage = null;
      }
      console.error('[LanguageSection] Failed to change language:', error);
    } finally {
      if (this.select) {
        this.select.disabled = false;
      }
      this.isProcessing = false;
    }
  }

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      const snapshot = this.extractLanguagePreference(
        options as Partial<LanguagePreferenceSnapshot>
      );
      if (!snapshot) {
        return;
      }
      if (this.pendingPersistLanguage && snapshot === this.pendingPersistLanguage) {
        this.pendingPersistLanguage = null;
        return;
      }
      if (snapshot === this.currentLanguage) {
        return;
      }
      void this.applyLanguage(snapshot, { persist: false });
    });
  }

  private extractLanguagePreference(options: Partial<LanguagePreferenceSnapshot>): Language | null {
    const pref = options.languagePreference?.code;
    return pref ?? null;
  }
}

import type { IOptionsRepository } from '@shared/repositories';
import type { PrivacyConsentSnapshot } from '@ui/domains/privacy';
import { PrivacySettings } from '@ui/domains/privacy';
import { BaseSection, type SectionRenderContext } from './BaseSection';
import { persistPrivacyConsentAction } from '../../app/actions';

export class PrivacySection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private host: HTMLElement | null = null;
  private instance: PrivacySettings | null = null;
  private unsubscribeFromRepo: (() => void) | null = null;
  private cachedConsent: PrivacyConsentSnapshot | null = null;

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(): HTMLElement {
    this.applySectionChrome();

    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);
    this.renderPrivacySettings();
    this.subscribeToRepository();
    return this.container;
  }

  async refreshSettings(): Promise<void> {
    this.renderPrivacySettings();
  }

  async saveSettings(options?: { showInlineStatus?: boolean }): Promise<void> {
    if (!this.instance && this.host) {
      this.renderPrivacySettings();
    }
    if (this.instance) {
      await this.instance.saveSettings(options);
    }
  }

  destroy(): void {
    this.instance = null;
    this.host = null;
    this.unsubscribeFromRepo?.();
    this.unsubscribeFromRepo = null;
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.privacySettingsTitle ?? '隐私与数据',
      description: this.messages?.privacySettingsDescription ?? '控制数据收集和错误报告'
    });
  }

  private buildBody(): HTMLElement {
    const container = this.createSectionBody();
    container.id = 'privacySettingsContainer';
    this.host = container;
    return container;
  }

  private renderPrivacySettings(): void {
    if (!this.host) {
      return;
    }

    try {
      // ✅ Stage 3 Week 2: PrivacySettings renders DaisyUI cards, checkboxes, and buttons
      this.instance = new PrivacySettings(this.host, {
        ...(this.cachedConsent !== undefined && { initialConsent: this.cachedConsent }),
        onConsentChange: (snapshot) => {
          this.cachedConsent = snapshot;
          this.persistConsent(snapshot);
        }
      });
      if (this.messages) {
        this.instance.setMessages(this.messages);
      }
      this.instance.render();
    } catch (error) {
      console.error('[PrivacySection] Failed to render privacy settings:', error);
      this.host.textContent =
        this.messages?.privacySettingsError ?? 'Failed to save settings, please try again.';
    }
  }

  private subscribeToRepository(): void {
    this.unsubscribeFromRepo?.();
    this.unsubscribeFromRepo = this.optionsRepo.onChange((options) => {
      const snapshot = this.extractConsentSnapshot(
        options as Partial<{ privacyPreferences?: PrivacyConsentSnapshot }>
      );
      if (snapshot) {
        this.cachedConsent = snapshot;
        this.instance?.applyConsentSnapshot(snapshot);
      }
    });
  }

  private extractConsentSnapshot(
    options: Partial<{ privacyPreferences?: PrivacyConsentSnapshot }>
  ): PrivacyConsentSnapshot | null {
    return options.privacyPreferences ?? null;
  }

  private persistConsent(snapshot: PrivacyConsentSnapshot): void {
    void persistPrivacyConsentAction(snapshot, {
      optionsRepository: this.optionsRepo
    })
      .catch((error) => {
        console.error(
          '[PrivacySection] Failed to persist privacy preferences via repository:',
          error
        );
      });
  }
}

import type { CompleteOptions, StoredOptions, ReadingSessionOptions } from '@shared/types/options';
import type { IOptionsRepository } from '@shared/repositories';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import { getOptionsController, markPendingAutoSave } from '../../app/optionsControllerContext';
import { type FormSectionHandlers } from '../formSections/formSectionManager';
import { UiButton as DaisyButton } from '@ui/primitives/button';
import { DaisyCard } from '@ui/primitives/card';
import { createOptionsHintText } from '@ui/primitives/layout';
import { DaisyRadioGroup } from '@ui/primitives/radio-group';
import { UiSelect as DaisySelect } from '@ui/primitives/select';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';

const HIGHLIGHT_THEMES = ['gradient', 'purple', 'neonYellow', 'neonGreen', 'neonOrange'] as const;
const HIGHLIGHT_THEME_CLASS_MAP: Record<(typeof HIGHLIGHT_THEMES)[number], string> = {
  gradient: 'bg-gradient-to-br from-[#7c3aed] to-[#3b82f6]',
  purple: 'bg-[#a855f7]',
  neonYellow: 'bg-[#facc15]',
  neonGreen: 'bg-[#4ade80]',
  neonOrange: 'bg-[#fb923c]'
};

export class ReadingSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private exportModeSelect: HTMLSelectElement | null = null;
  private themeContainer: HTMLElement | null = null;
  private themeButtons: HTMLButtonElement[] = [];
  private selectedTheme: string = HIGHLIGHT_THEMES[0];
  private previewHighlightSwatch: HTMLElement | null = null;
  private previewModeText: HTMLElement | null = null;
  private unsubscribeRepo: (() => void) | null = null;

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(_context: SectionRenderContext): HTMLElement {
    this.dispose();
    this.applySectionChrome(['transition-opacity', 'duration-200']);

    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);

    this.bindEvents();
    this.registerFormIntegration();
    this.subscribeToRepository();
    return this.container;
  }

  override destroy(): void {
    this.dispose();
    this.unregisterManagedFormSection();
    super.destroy();
  }

  private dispose(): void {
    if (this.exportModeSelect) {
      this.exportModeSelect.removeEventListener('change', this.handleValueChanged);
    }
    if (this.themeContainer) {
      this.themeContainer.removeEventListener('keydown', this.handleThemeKeydown);
    }
    this.themeButtons = [];
    this.exportModeSelect = null;
    this.themeContainer = null;
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;
  }

  private registerFormIntegration(): void {
    const binding: FormSectionHandlers = {
      applySnapshot: (options) => {
        this.applySnapshot(options);
      },
      collectChanges: (previous) => this.collectChanges(previous)
    };
    this.registerManagedFormSection('readingSession', binding);
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.readingConfigTitle ?? '阅读模式',
      description: this.messages?.readingConfigHint ?? '选择导出阅读模式时保存的内容形式'
    });
  }

  private buildBody(): HTMLElement {
    const wrapper = this.createElement('div', 'grid gap-6');
    const settings = this.createSectionSettings();

    const modeSetting = this.createSettingRow();
    const modeLabel = this.createElement('label', 'text-sm font-medium text-base-content/60', {
      for: 'readingExportMode'
    });
    modeLabel.textContent = this.messages?.readingExportModeLabel ?? '导出内容';
    const modeControl = this.createElement('div', 'flex flex-wrap justify-start gap-2');
    const modeSelectHost = this.createElement('div', 'w-full');
    const modeSelect = new DaisySelect(modeSelectHost).render({
      id: 'readingExportMode',
      options: [
        {
          value: 'highlights',
          label: this.messages?.readingExportModeHighlights ?? '仅保存高亮片段'
        },
        {
          value: 'full',
          label: this.messages?.readingExportModeFull ?? '保存全文并标注高亮'
        }
      ]
    });
    modeControl.append(modeSelectHost);
    const modeHint = createOptionsHintText({ tag: 'div' });
    modeHint.textContent =
      this.messages?.readingExportModeDescription ??
      '选择“全文”时，会同时保存经过清洗的原文，并在全文中保留你的高亮与脚注。';
    modeSetting.append(modeLabel, modeControl, modeHint);
    settings.append(modeSetting);
    this.exportModeSelect = modeSelect;

    const themeSetting = this.createSettingRow();
    const themeLabel = this.createElement('div', 'text-sm font-medium text-base-content/60');
    themeLabel.id = 'readingHighlightThemeLabel';
    themeLabel.textContent = this.messages?.readingHighlightThemeLabel ?? '高亮颜色';
    const themeOptionsHost = this.createElement('div');
    const themeOptions = new DaisyRadioGroup(themeOptionsHost).render({
      id: 'readingHighlightTheme',
      ariaLabelledBy: 'readingHighlightThemeLabel',
      value: HIGHLIGHT_THEMES[0],
      options: HIGHLIGHT_THEMES.map((theme) => ({
        value: theme,
        label: this.resolveThemeLabel(theme),
        srLabel: this.resolveThemeLabel(theme),
        swatchClassName: HIGHLIGHT_THEME_CLASS_MAP[theme]
      })),
      onChange: (theme) => {
        this.updateThemeSelection(theme);
        this.handleValueChanged();
      }
    });
    this.themeButtons = Array.from(
      themeOptions.querySelectorAll<HTMLButtonElement>('button[role="radio"]')
    );
    const themeHint = createOptionsHintText({ tag: 'div' });
    themeHint.textContent =
      this.messages?.readingHighlightThemeDescription ??
      '仅影响阅读模式页面的高亮背景，不会改变导出的 Markdown 内容。';
    themeSetting.append(themeLabel, themeOptionsHost, themeHint);
    settings.append(themeSetting);
    this.themeContainer = themeOptions;

    wrapper.append(settings, this.buildPreviewCard(), this.buildActionRow());
    // ⏸️ Stage 3 Month 3: Template editor pending Monaco/CodeMirror integration
    // 当前保留最简配置项，等待富文本模板能力落地后统一替换。
    return wrapper;
  }

  private bindEvents(): void {
    if (this.exportModeSelect) {
      this.exportModeSelect.addEventListener('change', () => {
        this.updatePreviewContent();
        this.handleValueChanged();
      });
    }

    if (this.themeContainer) {
      this.themeContainer.addEventListener('keydown', this.handleThemeKeydown);
    }
  }

  private handleValueChanged = (): void => {
    markPendingAutoSave('readingSession');
    const controller = getOptionsController();
    controller?.scheduleAutoSave();
  };

  private handleThemeKeydown = (event: KeyboardEvent): void => {
    if (!this.themeButtons.length) {
      return;
    }
    const currentIndex = this.themeButtons.findIndex(
      (button) => button.dataset.theme === this.selectedTheme
    );
    if (currentIndex === -1) {
      return;
    }

    let nextIndex = currentIndex;
    if (event.key === 'ArrowLeft' || event.key === 'ArrowUp') {
      nextIndex = (currentIndex - 1 + this.themeButtons.length) % this.themeButtons.length;
    } else if (event.key === 'ArrowRight' || event.key === 'ArrowDown') {
      nextIndex = (currentIndex + 1) % this.themeButtons.length;
    } else {
      return;
    }

    event.preventDefault();
    const nextButton = this.themeButtons[nextIndex];
    const theme = nextButton.dataset.theme;
    if (!theme) {
      return;
    }
    this.updateThemeSelection(theme);
    nextButton.focus();
    this.handleValueChanged();
  };

  private updateThemeSelection(theme: string): void {
    if (!this.themeContainer || !this.themeButtons.length) {
      return;
    }

    const normalized = HIGHLIGHT_THEMES.includes(theme as (typeof HIGHLIGHT_THEMES)[number])
      ? theme
      : HIGHLIGHT_THEMES[0];
    this.selectedTheme = normalized;
    this.themeContainer.dataset.selectedTheme = normalized;
    this.themeButtons.forEach((button) => {
      const isCurrent = button.dataset.theme === normalized;
      if (isCurrent) {
        button.classList.add('ring-2', 'ring-accent', 'ring-offset-2', 'ring-offset-surface-0');
      } else {
        button.classList.remove('ring-2', 'ring-accent', 'ring-offset-2', 'ring-offset-surface-0');
      }
      button.setAttribute('aria-checked', isCurrent ? 'true' : 'false');
      button.tabIndex = isCurrent ? 0 : -1;
    });
    this.updatePreviewContent();
  }

  private applySnapshot(options: StoredOptions): void {
    const readingSession = options.readingSession;
    const exportMode = readingSession?.exportMode ?? 'highlights';
    const highlightTheme = readingSession?.highlightTheme ?? HIGHLIGHT_THEMES[0];

    if (this.exportModeSelect) {
      this.exportModeSelect.value = exportMode;
    }
    this.updateThemeSelection(highlightTheme);
  }

  private collectChanges(previous: StoredOptions | null): Partial<CompleteOptions> {
    const previousReading = previous?.readingSession;

    const exportMode = this.exportModeSelect?.value ?? previousReading?.exportMode ?? 'highlights';
    const highlightTheme = HIGHLIGHT_THEMES.includes(
      this.selectedTheme as (typeof HIGHLIGHT_THEMES)[number]
    )
      ? (this.selectedTheme as (typeof HIGHLIGHT_THEMES)[number])
      : (previousReading?.highlightTheme ?? 'gradient');

    const partial: Partial<CompleteOptions> = {
      readingSession: {
        exportMode: exportMode as ReadingSessionOptions['exportMode'],
        highlightTheme: highlightTheme as ReadingSessionOptions['highlightTheme']
      }
    };
    return partial;
  }

  private buildPreviewCard(): HTMLElement {
    const host = this.createElement('div');
    const previewBody = this.createElement('div', 'space-y-3 text-sm text-base-content');
    const intro = this.createElement('p', 'm-0');
    intro.textContent =
      this.messages?.readingConfigHint ?? '根据当前导出方式与高亮主题预览保存效果：';

    const highlightPreview = this.createElement(
      'div',
      ['rounded-lg', 'border', 'border-base-300', 'bg-base-200/70', 'p-3'].join(' ')
    );
    const highlightSwatch = this.createElement(
      'span',
      [
        'inline-flex',
        'items-center',
        'px-3',
        'py-1',
        'text-xs',
        'font-semibold',
        'text-base-100',
        'rounded-full',
        'shadow-sm'
      ].join(' ')
    );
    highlightSwatch.textContent = this.messages?.readingHighlightThemeLabel ?? '示例高亮';
    highlightPreview.append(highlightSwatch);
    this.previewHighlightSwatch = highlightSwatch;

    const modeText = this.createElement('p', 'text-xs text-base-content/70 m-0');
    this.previewModeText = modeText;

    previewBody.append(intro, highlightPreview, modeText);

    const card = new DaisyCard(host);
    card.render({
      title: this.messages?.readingConfigTitle ?? '导出预览',
      body: previewBody
    });
    this.updatePreviewContent();
    return host;
  }

  private buildActionRow(): HTMLElement {
    const actionRow = this.createElement(
      'div',
      ['flex', 'flex-wrap', 'gap-3', 'items-center', 'border-t', 'border-base-300', 'pt-4'].join(
        ' '
      )
    );
    const saveHost = this.createElement('div');
    // ✅ Stage 3 Week 4: Migrated save button to DaisyButton (ReadingSection)
    new DaisyButton(saveHost).render({
      label: this.messages?.readingExportModeLabel ?? '保存阅读配置',
      variant: 'primary',
      size: 'sm',
      iconName: 'Save',
      onClick: () => {
        const controller = getOptionsController();
        controller?.scheduleAutoSave();
      }
    });
    actionRow.append(saveHost);
    return actionRow;
  }

  private updatePreviewContent(): void {
    if (!this.previewHighlightSwatch || !this.previewModeText) {
      return;
    }
    const theme = HIGHLIGHT_THEMES.includes(this.selectedTheme as (typeof HIGHLIGHT_THEMES)[number])
      ? (this.selectedTheme as (typeof HIGHLIGHT_THEMES)[number])
      : HIGHLIGHT_THEMES[0];
    this.previewHighlightSwatch.className = `inline-flex items-center px-3 py-1 text-xs font-semibold text-base-100 rounded-full shadow-sm ${HIGHLIGHT_THEME_CLASS_MAP[theme]}`;
    const modeValue = this.exportModeSelect?.value ?? 'highlights';
    const modeLabel =
      modeValue === 'full'
        ? (this.messages?.readingExportModeFull ?? '保存全文并标注高亮')
        : (this.messages?.readingExportModeHighlights ?? '仅保存高亮片段');
    this.previewModeText.textContent = `${modeLabel} · ${this.resolveThemeLabel(theme)}`;
  }

  private resolveThemeLabel(theme: (typeof HIGHLIGHT_THEMES)[number]): string {
    switch (theme) {
      case 'purple':
        return this.messages?.readingHighlightThemePurple ?? '纯紫色';
      case 'neonYellow':
        return this.messages?.readingHighlightThemeNeonYellow ?? '荧光黄';
      case 'neonGreen':
        return this.messages?.readingHighlightThemeNeonGreen ?? '荧光绿';
      case 'neonOrange':
        return this.messages?.readingHighlightThemeNeonOrange ?? '荧光橙';
      case 'gradient':
      default:
        return this.messages?.readingHighlightThemeGradient ?? '渐变紫蓝（默认）';
    }
  }

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      this.applySnapshot(options);
    });
  }
}

import type { CompleteOptions, RestOptions, StoredOptions } from '@shared/types/options';
import type { IOptionsRepository, IMessagingRepository } from '@shared/repositories';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import { configProvider } from '@shared/config';
import type { VaultConfig } from '@shared/types/vault';
import {
  subscribeVaultRouter,
  getVaultRouterConfig,
  initializeVaultRouterStore
} from '../../state/vaultRouterStore';
import { VaultRouterController } from '../controls/vaultRouterController';
import { type FormSectionHandlers } from '../formSections/formSectionManager';
import { UiAlert as DaisyAlert } from '@ui/primitives/alert';
import { getOptionsMessages } from '../../app/i18nContext';
import { getOptionsController, markPendingAutoSave } from '../../app/optionsControllerContext';
import { createConnectionTester, type ConnectionTester } from '../controls/connectionTest';
import type { ConnectionResultType } from '../../services/connectionTestRunner';
import { requestConnectionTest, requestVaultConnectionTest } from '../../services/connectionTester';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';
import {
  applyRestSectionSnapshot,
  collectAdditionalVaultConfigsForTest,
  collectRestDraftForTest,
  collectRestSectionChanges,
  readRestRowValue
} from './restSectionState';
import { buildRestSectionLayout, buildRestVaultRow, updateRestVaultRow } from './restSectionLayout';

const REST_DEFAULTS = configProvider.getRestDefaults();

export class RestSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private readonly messagingRepo: IMessagingRepository;
  private readonly vaultRouterController = new VaultRouterController();
  private defaultVaultId: string | null = null;
  private additionalRowsHost: HTMLElement | null = null;
  private additionalEmptyHint: HTMLElement | null = null;
  private unsubscribeVaultStore: (() => void) | null = null;
  private connectionTester: ConnectionTester | null = null;
  private connectionResultHost: HTMLDivElement | null = null;
  private unsubscribeRepo: (() => void) | null = null;

  private defaultNameInput: HTMLInputElement | null = null;
  private defaultHttpsInput: HTMLInputElement | null = null;
  private defaultHttpInput: HTMLInputElement | null = null;
  private defaultApiKeyInput: HTMLInputElement | null = null;
  private isApplyingSnapshot = false;

  constructor(
    container: HTMLElement,
    optionsRepo: IOptionsRepository,
    messagingRepo: IMessagingRepository
  ) {
    super(container);
    this.optionsRepo = optionsRepo;
    this.messagingRepo = messagingRepo;
  }

  protected renderWithState(_context: SectionRenderContext): HTMLElement {
    if (this.messages) {
      this.vaultRouterController.setMessages(this.messages);
    }
    this.vaultRouterController.render();
    this.applySectionChrome();

    this.defaultNameInput = null;
    this.defaultHttpsInput = null;
    this.defaultHttpInput = null;
    this.defaultApiKeyInput = null;

    const header = this.buildHeader();
    const body = this.buildBody();

    this.container.replaceChildren(header, body);

    this.unsubscribeVaultStore?.();
    this.unsubscribeVaultStore = subscribeVaultRouter((state) => {
      this.defaultVaultId =
        state.defaultVaultId ??
        state.vaults.find((vault) => vault.isDefault)?.id ??
        state.vaults[0]?.id ??
        null;
      this.renderAdditionalVaultRows(state.vaults, state.defaultVaultId);
    });

    const snapshot = getVaultRouterConfig();
    this.defaultVaultId =
      snapshot?.defaultVaultId ??
      snapshot?.vaults?.find((vault) => vault.isDefault)?.id ??
      snapshot?.vaults?.[0]?.id ??
      null;
    this.renderAdditionalVaultRows(snapshot?.vaults ?? [], snapshot?.defaultVaultId);
    this.subscribeToRepository();
    this.registerFormIntegration();
    this.initializeConnectionTester();

    return this.container;
  }

  override destroy(): void {
    this.unsubscribeVaultStore?.();
    this.unsubscribeVaultStore = null;
    this.additionalRowsHost = null;
    this.additionalEmptyHint = null;
    this.connectionTester?.dispose();
    this.connectionTester = null;
    this.connectionResultHost = null;
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;
    this.unregisterManagedFormSection();
    this.vaultRouterController.dispose();
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.apiConfigTitle ?? 'Obsidian Local REST API',
      description: this.messages?.apiConfigHint ?? '配置默认仓库和额外仓库的连接信息'
    });
  }

  private buildBody(): HTMLElement {
    const layout = buildRestSectionLayout({
      createElement: (tagName: string) =>
        this.createElement(tagName as keyof HTMLElementTagNameMap),
      messages: this.messages,
      updateDefaultVaultField: (field, value) => this.updateDefaultVaultField(field, value),
      addVault: () => this.vaultRouterController.addVault()
    });
    this.additionalRowsHost = layout.additionalRowsHost;
    this.additionalEmptyHint = layout.additionalEmptyHint;
    this.connectionResultHost = layout.connectionResultHost;
    this.defaultNameInput = layout.defaultNameInput;
    this.defaultHttpsInput = layout.defaultHttpsInput;
    this.defaultHttpInput = layout.defaultHttpInput;
    this.defaultApiKeyInput = layout.defaultApiKeyInput;
    return layout.body;
  }

  private renderConnectionTestResult(type: ConnectionResultType, text: string): void {
    if (!this.connectionResultHost) {
      return;
    }
    this.connectionResultHost.hidden = false;
    this.connectionResultHost.replaceChildren();
    const [message, ...rest] = text.split('\n');
    const description = rest.join('\n').trim() || undefined;
    // ✅ Stage 3 Week 3: Migrated connection result alert to DaisyAlert (RestSection)
    const alert = new DaisyAlert(this.connectionResultHost);
    alert.render({
      type: type === 'success' ? 'success' : type === 'error' ? 'error' : 'info',
      message: message || text,
      ...(description !== undefined && { description }),
      dismissible: type !== 'info'
    });
  }

  private resetConnectionTestResult(): void {
    if (!this.connectionResultHost) {
      return;
    }
    this.connectionResultHost.hidden = true;
    this.connectionResultHost.replaceChildren();
  }

  private renderAdditionalVaultRows(vaults: VaultConfig[], defaultVaultId?: string): void {
    if (!this.additionalRowsHost || !this.additionalEmptyHint) {
      return;
    }

    const additional = vaults.filter((vault) => vault.id !== (defaultVaultId ?? vaults[0]?.id));

    const existingRows = new Map<string, HTMLElement>();
    this.additionalRowsHost.querySelectorAll<HTMLElement>('[data-vault-id]').forEach((row) => {
      if (row.dataset.vaultId) {
        existingRows.set(row.dataset.vaultId, row);
      }
    });

    const seen = new Set<string>();

    for (const vault of additional) {
      seen.add(vault.id);
      const existing = existingRows.get(vault.id);
      if (existing) {
        updateRestVaultRow(existing, vault);
      } else {
        this.additionalRowsHost.append(
          buildRestVaultRow({
            createElement: (tagName: string) =>
              this.createElement(tagName as keyof HTMLElementTagNameMap),
            messages: this.messages,
            vault,
            updateVault: (vaultId, updates) =>
              this.vaultRouterController.updateVault(vaultId, updates),
            removeVault: (vaultId) => this.vaultRouterController.removeVault(vaultId)
          })
        );
      }
    }

    for (const [id, row] of existingRows) {
      if (!seen.has(id)) {
        row.remove();
      }
    }

    this.additionalEmptyHint.hidden = this.additionalRowsHost.childElementCount > 0;
  }

  private updateDefaultVaultField(
    field: 'name' | 'httpsUrl' | 'httpUrl' | 'apiKey',
    rawValue: string
  ): void {
    if (!this.isApplyingSnapshot) {
      markPendingAutoSave('rest');
      getOptionsController()?.scheduleAutoSave();
    }

    if (!this.defaultVaultId) {
      return;
    }

    const updates: Partial<VaultConfig> = {};

    if (field === 'name') {
      const trimmed = rawValue.trim();
      updates.vault = trimmed;
      updates.name = trimmed;
    } else if (field === 'httpsUrl') {
      updates.httpsUrl = rawValue.trim();
    } else if (field === 'httpUrl') {
      updates.httpUrl = rawValue.trim();
    } else if (field === 'apiKey') {
      updates.apiKey = rawValue;
    }

    this.vaultRouterController.updateVault(this.defaultVaultId, updates, {
      silent: this.isApplyingSnapshot
    });
  }

  private registerFormIntegration(): void {
    const binding: FormSectionHandlers = {
      applySnapshot: (options) => {
        this.applySnapshot(options);
      },
      collectChanges: (previous) => this.collectChanges(previous)
    };
    this.registerManagedFormSection('rest', binding);
  }

  private applySnapshot(options: StoredOptions | CompleteOptions): void {
    initializeVaultRouterStore(options.vaultRouter ?? null);
    const router = getVaultRouterConfig() ?? null;

    this.isApplyingSnapshot = true;
    const resolved = applyRestSectionSnapshot({
      options,
      defaultInputs: {
        nameInput: this.defaultNameInput,
        httpsInput: this.defaultHttpsInput,
        httpInput: this.defaultHttpInput,
        apiKeyInput: this.defaultApiKeyInput
      },
      defaultVaultId: this.defaultVaultId,
      vaultRouterSnapshot: router,
      defaults: REST_DEFAULTS
    });
    if (this.defaultVaultId) {
      this.updateDefaultVaultField('name', resolved.name);
      this.updateDefaultVaultField('httpsUrl', resolved.httpsUrl);
      this.updateDefaultVaultField('httpUrl', resolved.httpUrl);
      this.updateDefaultVaultField('apiKey', resolved.apiKey);
    }
    this.isApplyingSnapshot = false;
  }

  private collectChanges(previous: StoredOptions | null): Partial<CompleteOptions> {
    const partial = collectRestSectionChanges({
      previous,
      defaultInputs: {
        nameInput: this.defaultNameInput,
        httpsInput: this.defaultHttpsInput,
        httpInput: this.defaultHttpInput,
        apiKeyInput: this.defaultApiKeyInput
      },
      defaults: REST_DEFAULTS
    });
    return partial;
  }

  private initializeConnectionTester(): void {
    this.connectionTester?.dispose();
    const button = this.container.querySelector<HTMLButtonElement>('#testConnectionBtn');
    const resultHost = this.container.querySelector<HTMLDivElement>('#connectionResult');
    if (!button || !resultHost) {
      this.connectionTester = null;
      return;
    }
    this.connectionTester = createConnectionTester({
      button,
      resultHost,
      getMessages: getOptionsMessages,
      getRestDraft: () => this.collectRestDraftForTest(),
      getAdditionalVaultConfigs: () => this.collectAdditionalVaultConfigsForTest(),
      renderResult: (_host, type, text) => this.renderConnectionTestResult(type, text),
      resetResult: () => this.resetConnectionTestResult(),
      runDefaultTest: (draft) => requestConnectionTest(draft, this.messagingRepo),
      runVaultTest: (vault) => requestVaultConnectionTest(vault, this.messagingRepo)
    });
  }

  private collectRestDraftForTest(): Partial<RestOptions> {
    return collectRestDraftForTest({
      nameInput: this.defaultNameInput,
      httpsInput: this.defaultHttpsInput,
      httpInput: this.defaultHttpInput,
      apiKeyInput: this.defaultApiKeyInput
    });
  }

  private collectAdditionalVaultConfigsForTest(): VaultConfig[] {
    return collectAdditionalVaultConfigsForTest({
      additionalRowsHost: this.additionalRowsHost,
      vaultRouterSnapshot: getVaultRouterConfig() ?? null,
      defaultVaultId: this.defaultVaultId
    });
  }

  private readRowValue(row: HTMLElement, selector: string, trim = true): string | null {
    return readRestRowValue(row, selector, trim);
  }

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      this.applySnapshot(options);
    });
  }
}

import type { CompleteOptions } from '@shared/types/options';
import type { VaultConfig, RoutingRule, RoutingRuleType } from '@shared/types/vault';
import type { IOptionsRepository } from '@shared/repositories';
import { resolveRepository } from '@shared/di/serviceRegistry';
import { DI_TOKENS } from '@shared/di/tokens';
import {
  subscribeVaultRouter,
  getVaultRouterConfig,
  initializeVaultRouterStore
} from '../../state/vaultRouterStore';
import { VaultRouterController } from '../controls/vaultRouterController';
import { VaultRouterView } from '@ui/domains/vault-router';
import { getOptionsController, markPendingAutoSave } from '../../app/optionsControllerContext';
import { type FormSectionHandlers } from '../formSections/formSectionManager';
import type { SectionRenderContext } from './BaseSection';
import { BaseSection } from './BaseSection';

export class RoutingSection extends BaseSection<SectionRenderContext> {
  private readonly optionsRepo: IOptionsRepository;
  private readonly vaultRouterController = new VaultRouterController();
  private vaultRouterView: VaultRouterView | null = null;
  private unsubscribeVaultStore: (() => void) | null = null;
  private unsubscribeRepo: (() => void) | null = null;

  constructor(container: HTMLElement, optionsRepo: IOptionsRepository) {
    super(container);
    this.optionsRepo = optionsRepo;
  }

  protected renderWithState(_context: SectionRenderContext): HTMLElement {
    this.applySectionChrome();

    if (this.messages) {
      this.vaultRouterController.setMessages(this.messages);
    }
    this.vaultRouterController.render({
      onChange: this.handleVaultRouterChange,
      autoSave: false
    });

    const header = this.buildHeader();
    const body = this.buildBody();
    this.container.replaceChildren(header, body);

    this.mountVaultRouterView();
    this.unsubscribeVaultStore?.();
    this.unsubscribeVaultStore = subscribeVaultRouter((state) => {
      this.renderRoutingState(state.vaults, state.defaultVaultId);
    });

    const snapshot = getVaultRouterConfig();
    this.renderRoutingState(snapshot?.vaults ?? [], snapshot?.defaultVaultId);
    this.subscribeToRepository();
    this.registerFormIntegration();

    return this.container;
  }

  override destroy(): void {
    this.unsubscribeVaultStore?.();
    this.unsubscribeVaultStore = null;
    this.unregisterManagedFormSection();
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = null;
    this.vaultRouterView?.destroy();
    this.vaultRouterView = null;
    this.vaultRouterController.dispose();
    super.destroy();
  }

  private buildHeader(): HTMLElement {
    return this.buildSectionHeader({
      title: this.messages?.routingRulesTitle ?? '路由规则',
      description:
        this.messages?.routingRulesHint ?? '根据域名、关键词或 URL 模式自动选择目标仓库。'
    });
  }

  private buildBody(): HTMLElement {
    const pad = this.createSectionBody();
    const viewHost = this.createElement('div', 'space-y-4', { id: 'vaultRouterViewHost' });
    const note = this.createElement('p', 'text-sm text-base-content/60');
    note.textContent =
      this.messages?.routingRulesPriorityNote ?? '提示：优先级越高越先匹配，目标仓库需保持启用。';
    pad.append(viewHost, note);
    return pad;
  }

  private mountVaultRouterView(): void {
    const host = this.container.querySelector<HTMLElement>('#vaultRouterViewHost');
    if (!host) {
      throw new Error('[RoutingSection] Vault router view host missing.');
    }

    this.vaultRouterView?.destroy();
    this.vaultRouterView = new VaultRouterView(host);
    if (this.messages) {
      this.vaultRouterView.setMessages(this.messages);
    }

    this.vaultRouterView.render({
      labels: {
        enabled: this.messages?.ruleEnabledLabel ?? '启用',
        type: this.messages?.ruleTypeLabel ?? '规则类型',
        pattern: this.messages?.rulePatternLabel ?? '匹配模式',
        targetVault: this.messages?.ruleTargetVaultLabel ?? '目标仓库',
        priority: this.messages?.rulePriorityLabel ?? '优先级',
        actions: this.messages?.yamlFieldActionsLabel ?? '操作',
        addRule: this.messages?.addRuleButton ?? '+ 添加规则',
        deleteRule: this.messages?.deleteRuleButton ?? '删除',
        empty: this.messages?.ruleEmptyPlaceholder ?? '暂无规则，点击右侧按钮为仓库添加规则',
        patternPlaceholder:
          this.messages?.rulePatternPlaceholder ??
          '例如：example.com;news.example.com 或 关键词1,关键词2',
        defaultVaultBadge: this.messages?.defaultVaultBadge ?? '默认仓库',
        typeDomain: this.messages?.ruleTypeDomain ?? '域名匹配',
        typeKeyword: this.messages?.ruleTypeKeyword ?? '关键词匹配',
        typeUrlPattern: this.messages?.ruleTypeUrlPattern ?? 'URL 模式',
        enabledAria: this.messages?.ruleEnabledLabel ?? '启用规则',
        typeAria: this.messages?.ruleTypeLabel ?? '规则类型',
        patternAria: this.messages?.rulePatternLabel ?? '匹配模式',
        targetAria: this.messages?.ruleTargetVaultLabel ?? '目标仓库',
        priorityAria: this.messages?.rulePriorityLabel ?? '优先级'
      },
      onAddRule: this.handleAddRule,
      onToggleEnabled: this.handleToggleRuleEnabled,
      onChangeType: this.handleChangeRuleType,
      onChangePattern: this.handleChangeRulePattern,
      onChangeTarget: this.handleChangeRuleTarget,
      onChangePriority: this.handleChangeRulePriority,
      onRemoveRule: this.handleRemoveRule
    });
  }

  private renderRoutingState(vaults: VaultConfig[], defaultVaultId?: string): void {
    const rules: RoutingRule[] = [];
    for (const vault of vaults) {
      for (const rule of vault.rules ?? []) {
        rules.push(rule);
      }
    }

    const resolvedDefaultId =
      defaultVaultId ?? vaults.find((vault) => vault.isDefault)?.id ?? vaults[0]?.id ?? '';
    const defaultBadge = this.messages?.defaultVaultBadge ?? '默认仓库';
    const vaultOptions = vaults.map((vault) => {
      const trimmedName = vault.name?.trim() ?? '';
      const trimmedVault = vault.vault?.trim() ?? '';
      const isDefaultVault = vault.id === resolvedDefaultId || vault.isDefault === true;
      const displayName = isDefaultVault
        ? trimmedVault || trimmedName || defaultBadge
        : trimmedName || trimmedVault || vault.id;
      return {
        id: vault.id,
        name: displayName,
        disabled: vault.enabled === false
      };
    });

    this.vaultRouterView?.update({
      rules,
      vaultOptions,
      ...(resolvedDefaultId ? { defaultVaultId: resolvedDefaultId } : {})
    });
  }

  private registerFormIntegration(): void {
    const binding: FormSectionHandlers = {
      applySnapshot: (options) => {
        initializeVaultRouterStore(options.vaultRouter ?? null);
      },
      collectChanges: () => {
        const config = getVaultRouterConfig();
        if (config) {
          return { vaultRouter: config };
        }
        return {};
      }
    };
    this.registerManagedFormSection('routing', binding);
  }

  private handleAddRule = (): void => {
    const snapshot = getVaultRouterConfig();
    const defaultVaultId =
      snapshot?.defaultVaultId ??
      snapshot?.vaults?.find((vault) => vault.isDefault)?.id ??
      snapshot?.vaults?.[0]?.id;
    this.vaultRouterController.addRule(defaultVaultId ? { vaultId: defaultVaultId } : {});
    this.triggerAutoSave();
  };

  private handleToggleRuleEnabled = (ruleId: string, enabled: boolean): void => {
    this.vaultRouterController.updateRule(ruleId, { enabled });
    this.triggerAutoSave();
  };

  private handleChangeRuleType = (ruleId: string, type: RoutingRuleType): void => {
    this.vaultRouterController.updateRule(ruleId, { type });
    this.triggerAutoSave();
  };

  private handleChangeRulePattern = (ruleId: string, pattern: string): void => {
    this.vaultRouterController.updateRule(ruleId, { pattern });
    this.triggerAutoSave();
  };

  private handleChangeRuleTarget = (ruleId: string, vaultId: string): void => {
    this.vaultRouterController.updateRule(ruleId, { vaultId });
    this.triggerAutoSave();
  };

  private handleChangeRulePriority = (ruleId: string, priority: number): void => {
    this.vaultRouterController.updateRule(ruleId, { priority });
    this.triggerAutoSave();
  };

  private handleRemoveRule = (ruleId: string): void => {
    this.vaultRouterController.removeRule(ruleId);
    this.triggerAutoSave();
  };

  private triggerAutoSave(): void {
    markPendingAutoSave('routing');
    markPendingAutoSave('vaultRouter');
    getOptionsController()?.scheduleAutoSave();
  }

  private handleVaultRouterChange = (): void => {
    this.triggerAutoSave();
  };

  private subscribeToRepository(): void {
    this.unsubscribeRepo?.();
    this.unsubscribeRepo = this.optionsRepo.onChange((options) => {
      initializeVaultRouterStore(options.vaultRouter ?? null);
    });
  }
}

