        value: 'MacIntel',
        configurable: true
      });

      const dialog = await createDialog();

      const resultPromise = dialog.show('Test selection');
      await flushPromises();

      const textarea = getTextarea();
      textarea.value = 'Test comment';

      textarea.dispatchEvent(new KeyboardEvent('keydown', { 
        key: 'Enter',
