        value: 'Win32',
        configurable: true
      });

      const dialog = await createDialog();

      const resultPromise = dialog.show('Test selection');
      await flushPromises();

      const textarea = getTextarea();
      textarea.value = 'Test comment';

      textarea.dispatchEvent(new KeyboardEvent('keydown', { 
        key: 'Enter',
        altKey: true,
        bubbles: true, 
        cancelable: true 
      }));

      const result = await resultPromise;
      expect(result).toEqual({ action: 'clip', comment: 'Test comment' });
    });

    it('double-enter triggers clip action in reader mode', async () => {
      // Mock reader mode
      registerReaderSession({ id: 'reader-session' }, document);

      const dialog = await createDialog();

      const resultPromise = dialog.show('Test selection');
      await flushPromises();

      const textarea = getTextarea();
      textarea.value = 'Test comment';

      // First Enter
      textarea.dispatchEvent(new KeyboardEvent('keydown', { 
        key: 'Enter', 
        bubbles: true, 
        cancelable: true 
      }));

      // Second Enter within 600ms
      setTimeout(() => {
        textarea.dispatchEvent(new KeyboardEvent('keydown', { 
          key: 'Enter', 
          bubbles: true, 
          cancelable: true 
        }));
      }, 100);

      const result = await resultPromise;
      expect(result).toEqual({ action: 'clip', comment: 'Test comment' });
