import { beforeEach, describe, expect, it, vi } from 'vitest';
import { ChromeClipRepository } from '../../../src/infrastructure/repositories/ChromeClipRepository';
import type { IMessagingRepository } from '@shared/repositories';
import type { ClipData, ClipResult, FragmentConfig } from '@shared/repositories/IClipRepository';
import type { IOptionsRepository } from '@shared/repositories/IOptionsRepository';
import type { CompleteOptions } from '@shared/types/options';

const createMockFn = <T extends (...args: any[]) => any>() => vi.fn<Parameters<T>, ReturnType<T>>();

const clone = <T>(value: T): T => JSON.parse(JSON.stringify(value)) as T;

const createOptionsSnapshot = (): CompleteOptions =>
  clone({
    rest: {
      baseUrl: 'https://obsidian.example/',
      httpsUrl: 'https://obsidian.example/',
      httpUrl: 'http://obsidian.example/',
      vault: 'AllInObsidian',
      apiKey: 'test-key'
    },
    templates: {
      article: 'article template',
      fragment: 'fragment template',
      reading: 'reading template',
      ai: 'ai template'
    },
    fragmentClipper: {
      useFootnoteFormat: true,
      captureContext: true,
      contextLength: 200,
      contextMode: 'chars',
      selectionModifierEnabled: false,
      selectionModifierKeys: []
    }
  } as unknown as CompleteOptions);

type OptionsRepoMock = IOptionsRepository & {
  get: ReturnType<typeof createMockFn<IOptionsRepository['get']>>;
  set: ReturnType<typeof createMockFn<IOptionsRepository['set']>>;
  onChange: ReturnType<typeof createMockFn<IOptionsRepository['onChange']>>;
};

type MessagingRepoMock = IMessagingRepository & {
  send: ReturnType<typeof createMockFn<IMessagingRepository['send']>>;
  onMessage: ReturnType<typeof createMockFn<IMessagingRepository['onMessage']>>;
};

describe('ChromeClipRepository', () => {
  let repo: ChromeClipRepository;
  let optionsSnapshot: CompleteOptions;

  const mockOptionsRepo: OptionsRepoMock = {
    get: createMockFn<IOptionsRepository['get']>(),
    set: createMockFn<IOptionsRepository['set']>(),
    onChange: createMockFn<IOptionsRepository['onChange']>()
  };

  const mockMessagingRepo: MessagingRepoMock = {
    send: createMockFn<IMessagingRepository['send']>() as MessagingRepoMock['send'],
    onMessage: createMockFn<IMessagingRepository['onMessage']>()
  };

  beforeEach(() => {
    optionsSnapshot = createOptionsSnapshot();
    mockOptionsRepo.get.mockResolvedValue(optionsSnapshot);
    mockOptionsRepo.set.mockResolvedValue();
    mockOptionsRepo.onChange.mockImplementation((listener) => {
      listener(optionsSnapshot);
      return vi.fn();
    });
    repo = new ChromeClipRepository(mockOptionsRepo, mockMessagingRepo);
  });

  describe('getFragmentConfig()', () => {
    it('returns cloned fragment config from options', async () => {
      const result = await repo.getFragmentConfig();
      expect(result).toEqual(optionsSnapshot.fragmentClipper);
      expect(result).not.toBe(optionsSnapshot.fragmentClipper);

      result.contextLength = 999;
      const fresh = await repo.getFragmentConfig();
      expect(fresh.contextLength).toBe(optionsSnapshot.fragmentClipper.contextLength);
    });
  });

  describe('setFragmentConfig()', () => {
    it('merges incoming config with existing fragment config', async () => {
      const partial: Partial<FragmentConfig> = {
        captureContext: false,
        contextLength: 512
      };

      await repo.setFragmentConfig(partial);

      expect(mockOptionsRepo.set).toHaveBeenCalledWith({
        fragmentClipper: {
          ...optionsSnapshot.fragmentClipper,
          ...partial
        }
      });
    });

    it('reflects merged config when getFragmentConfig is called afterwards', async () => {
      mockOptionsRepo.set.mockImplementation((payload: Partial<CompleteOptions>) => {
        if (payload.fragmentClipper) {
          optionsSnapshot.fragmentClipper = clone(payload.fragmentClipper);
        }
        return Promise.resolve();
      });

      await repo.setFragmentConfig({ contextLength: 321 });
      const config = await repo.getFragmentConfig();
      expect(config.contextLength).toBe(321);
    });
  });

  describe('getTemplateConfig()', () => {
    it('returns cloned template config', async () => {
      const result = await repo.getTemplateConfig();
      expect(result).toEqual(optionsSnapshot.templates);
      expect(result).not.toBe(optionsSnapshot.templates);

      result.article = 'mutated';
      const fresh = await repo.getTemplateConfig();
      expect(fresh.article).toBe(optionsSnapshot.templates.article);
    });
  });

  describe('sendClip()', () => {
    const clipPayload: ClipData = {
      type: 'article',
      title: 'Sample',
      markdown: 'markdown content',
      content: 'markdown',
      url: 'https://example.com'
    };

    it('returns result from messaging repository when successful', async () => {
      const expected: ClipResult = { success: true, filePath: '/vault/sample.md' };
      mockMessagingRepo.send.mockResolvedValue(expected);

      const result = await repo.sendClip(clipPayload);

      expect(mockMessagingRepo.send).toHaveBeenCalledWith({
        type: 'clip',
        data: clipPayload
      });
      expect(result).toEqual(expected);
    });

    it('returns failure result when messaging throws errors', async () => {
      mockMessagingRepo.send.mockRejectedValue(new Error('message failed'));

      const result = await repo.sendClip(clipPayload);

      expect(result).toEqual({
        success: false,
        error: 'message failed'
      });
    });

    it('handles non Error exceptions gracefully', async () => {
      mockMessagingRepo.send.mockRejectedValue('string failure');

      const result = await repo.sendClip(clipPayload);

      expect(result).toEqual({
        success: false,
        error: 'Unknown error'
      });
    });
  });

  describe('onConfigChange()', () => {
    it('subscribes to options repository and emits cloned config', () => {
      let emittedConfig: FragmentConfig | null = null;
      const callback = vi.fn((config: FragmentConfig) => {
        emittedConfig = config;
      });
      const unsubscribe = repo.onConfigChange(callback);

      expect(mockOptionsRepo.onChange).toHaveBeenCalledTimes(1);
      expect(callback).toHaveBeenCalledWith(optionsSnapshot.fragmentClipper);
      expect(emittedConfig).not.toBe(optionsSnapshot.fragmentClipper);

      unsubscribe();
    });

    it('propagates changes when options repository emits new fragment config', () => {
      let listener: ((options: CompleteOptions) => void) | null = null;
      mockOptionsRepo.onChange.mockImplementation((next) => {
        listener = next;
        return vi.fn();
      });
      let latestConfig: FragmentConfig | null = null;
      const callback = vi.fn((config: FragmentConfig) => {
        latestConfig = config;
      });
      repo.onConfigChange(callback);

      const updated = createOptionsSnapshot();
      updated.fragmentClipper.contextLength = 777;
      if (!listener) {
        throw new Error('options listener missing');
      }
      (listener as (options: CompleteOptions) => void)(updated);

      expect(callback).toHaveBeenCalledWith(updated.fragmentClipper);
      expect(latestConfig).not.toBe(updated.fragmentClipper);
    });
  });

  describe('environment compatibility', () => {
    it('uses global structuredClone when available for deep cloning', async () => {
      const globalRef = globalThis as typeof globalThis & { structuredClone?: <T>(value: T) => T };
      const originalStructuredClone = globalRef.structuredClone;
      const structuredSpy = vi.fn(<T>(value: T) => JSON.parse(JSON.stringify(value)) as T);
      globalRef.structuredClone = structuredSpy;

      try {
        await repo.getFragmentConfig();
        await repo.getTemplateConfig();
        expect(structuredSpy).toHaveBeenCalled();
      } finally {
        globalRef.structuredClone = originalStructuredClone;
      }
    });

    it('falls back to JSON cloning when structuredClone is unavailable', async () => {
      const globalRef = globalThis as typeof globalThis & { structuredClone?: <T>(value: T) => T };
      const originalStructuredClone = globalRef.structuredClone;
      Reflect.deleteProperty(globalRef, 'structuredClone');

      try {
        const fragment = await repo.getFragmentConfig();
        fragment.contextLength = 999;
        const fresh = await repo.getFragmentConfig();
        expect(fresh.contextLength).toBe(optionsSnapshot.fragmentClipper.contextLength);
      } finally {
        globalRef.structuredClone = originalStructuredClone;
      }
    });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { ChromeMessagingRepository } from '../../../src/infrastructure/repositories/ChromeMessagingRepository';
import { MessagingError } from '@shared/errors';
import type { Message, MessageSender } from '@shared/repositories';
import type { MessagingService, MessageListener } from '../../../src/platform/interfaces/messaging';

type PlatformListener = (message: Message, sender: MessageSender) => Promise<unknown> | void;
const createMockFn = <T extends (...args: any[]) => any>() => vi.fn<Parameters<T>, ReturnType<T>>();

const removeListener = vi.fn();
type MessagingServiceMock = MessagingService & {
  send: ReturnType<typeof createMockFn<MessagingService['send']>>;
  sendToTab: ReturnType<typeof createMockFn<MessagingService['sendToTab']>>;
  addListener: ReturnType<typeof createMockFn<MessagingService['addListener']>>;
};

const mockMessaging: MessagingServiceMock = {
  send: createMockFn<MessagingService['send']>() as MessagingServiceMock['send'],
  sendToTab: createMockFn<MessagingService['sendToTab']>() as MessagingServiceMock['sendToTab'],
  addListener: createMockFn<MessagingService['addListener']>() as MessagingServiceMock['addListener']
};

let registeredListener: PlatformListener | null = null;

describe('ChromeMessagingRepository', () => {
  let repo: ChromeMessagingRepository;

  beforeEach(() => {
    vi.clearAllMocks();
    registeredListener = null;
    mockMessaging.addListener.mockImplementation((listener: MessageListener) => {
      registeredListener = listener as PlatformListener;
      return removeListener;
    });
    repo = new ChromeMessagingRepository(mockMessaging);
  });

  describe('send()', () => {
    it('should forward message to platform messaging service and resolve response', async () => {
      const message: Message = { type: 'track', event: 'options_opened' };
      const payload = { ok: true };
      mockMessaging.send.mockResolvedValue(payload);

      const response = await repo.send<typeof payload>(message);

      expect(mockMessaging.send).toHaveBeenCalledWith(message);
      expect(response).toEqual(payload);
    });

    it('should rethrow MessagingError emitted by platform service', async () => {
      const message: Message = { type: 'track', event: 'options_closed' };
      const platformError = new MessagingError('platform failure');
      mockMessaging.send.mockRejectedValue(platformError);

      await expect(repo.send(message)).rejects.toBe(platformError);
    });

    it('should wrap unknown errors as MessagingError', async () => {
      const message: Message = { type: 'clip', data: { markdown: '# test clip', title: 'mock' } };
      mockMessaging.send.mockRejectedValue(new Error('disconnected'));

      const attempt = repo.send(message);

      await expect(attempt).rejects.toBeInstanceOf(MessagingError);
      await expect(attempt).rejects.toThrow('Failed to send message to background');
    });

    it('should timeout when response exceeds limit', async () => {
      vi.useFakeTimers();
      try {
        const message: Message = { type: 'track', event: 'slow_response' };
        mockMessaging.send.mockReturnValue(new Promise(() => {}));

        const attempt = repo.send(message, 50);
        const assertion = expect(attempt).rejects.toThrow('Message timeout after waiting for response');

        await vi.advanceTimersByTimeAsync(50);
        await assertion;
      } finally {
        vi.useRealTimers();
      }
    });
  });

  describe('onMessage()', () => {
    it('should register listener through platform messaging service', () => {
      const handler = vi.fn();

      repo.onMessage(handler);

      expect(mockMessaging.addListener).toHaveBeenCalledTimes(1);
      expect(typeof registeredListener).toBe('function');
    });

    it('should invoke handler when platform listener receives message', async () => {
      const handler = vi.fn().mockResolvedValue('ok');
      repo.onMessage(handler);
      const incoming: Message = { type: 'track', event: 'button_click' };
      const sender: MessageSender = { id: 'sender', tabId: 42 };

      const listener = registeredListener;
      expect(listener).toBeTruthy();
      if (!listener) {
        throw new Error('Listener not registered');
      }

      const result = await listener(incoming, sender);

      expect(handler).toHaveBeenCalledWith(incoming, sender);
      expect(result).toBe('ok');
    });

    it('should return unsubscribe function from platform service', () => {
      const handler = vi.fn();

      const unsubscribe = repo.onMessage(handler);

      expect(typeof unsubscribe).toBe('function');
      unsubscribe();
      expect(removeListener).toHaveBeenCalledTimes(1);
    });
  });
});

import { beforeEach, describe, expect, it, vi } from 'vitest';
import { ChromeOptionsRepository } from '../../../src/infrastructure/repositories/ChromeOptionsRepository';
import { DEFAULT_OPTIONS } from '@shared/config/defaultOptions';
import { StorageError } from '@shared/errors';
import type { CompleteOptions } from '@shared/types/options';
import type { StorageAreaService, StorageService } from '../../../src/platform/interfaces/storage';

const createMockFn = <T extends (...args: any[]) => any>() => vi.fn<Parameters<T>, ReturnType<T>>();

type StorageAreaMock = StorageAreaService & {
  get: ReturnType<typeof createMockFn<StorageAreaService['get']>>;
  set: ReturnType<typeof createMockFn<StorageAreaService['set']>>;
  getMany: ReturnType<typeof createMockFn<StorageAreaService['getMany']>>;
  setMany: ReturnType<typeof createMockFn<StorageAreaService['setMany']>>;
  remove: ReturnType<typeof createMockFn<StorageAreaService['remove']>>;
  clear: ReturnType<typeof createMockFn<StorageAreaService['clear']>>;
  watchKey: ReturnType<typeof createMockFn<StorageAreaService['watchKey']>>;
  watchAll: ReturnType<typeof createMockFn<StorageAreaService['watchAll']>>;
};

// ===========================
// Helper Functions
// ===========================
function cloneOptions(options: CompleteOptions): CompleteOptions {
  const cloned = JSON.parse(JSON.stringify(options)) as CompleteOptions;
  cloned.rest.apiKey = 'test-api-key-12345';
  return cloned;
}

// ===========================
// Mock Platform Services
// ===========================
const createStorageAreaMock = (): StorageAreaMock => {
  const watchKey = createMockFn<StorageAreaService['watchKey']>().mockReturnValue(vi.fn());
  const watchAll = createMockFn<StorageAreaService['watchAll']>().mockReturnValue(vi.fn());
  return {
    get: createMockFn<StorageAreaService['get']>() as StorageAreaMock['get'],
    set: createMockFn<StorageAreaService['set']>(),
    getMany: createMockFn<StorageAreaService['getMany']>() as StorageAreaMock['getMany'],
    setMany: createMockFn<StorageAreaService['setMany']>(),
    remove: createMockFn<StorageAreaService['remove']>(),
    clear: createMockFn<StorageAreaService['clear']>(),
    watchKey,
    watchAll
  } as StorageAreaMock;
};

const mockStorage: StorageService & {
  sync: StorageAreaMock;
  local: StorageAreaMock;
  session: StorageAreaMock;
} = {
  sync: createStorageAreaMock(),
  local: createStorageAreaMock(),
  session: createStorageAreaMock()
};

// ===========================
// Test Suite
// ===========================
describe('ChromeOptionsRepository', () => {
  let repo: ChromeOptionsRepository;

  beforeEach(() => {
    vi.clearAllMocks();
    mockStorage.sync.get.mockReset();
    mockStorage.sync.set.mockReset();
    mockStorage.sync.watchKey.mockReset();
    mockStorage.sync.watchAll.mockReset();
    mockStorage.sync.set.mockResolvedValue(undefined);
    repo = new ChromeOptionsRepository(mockStorage);
  });

  // ===========================
  // 核心验证：onChange 单次触发
  // ===========================
  describe('onChange triggering', () => {
    it('should trigger onChange callback exactly ONCE when set() is called', async () => {
      const initialOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      initialOptions.rest.baseUrl = 'https://initial.example/';

      const updatedOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      updatedOptions.rest.baseUrl = 'https://updated.example/';

      // Setup: Initial get returns initial state
      mockStorage.sync.get.mockResolvedValueOnce(initialOptions);

      // Setup: Second get (for set() merge) returns initial state
      mockStorage.sync.get.mockResolvedValueOnce(initialOptions);

      // Setup: Third get (for notifyListeners) returns updated state
      mockStorage.sync.get.mockResolvedValueOnce(updatedOptions);

      const callback = vi.fn();

      // Subscribe to onChange
      repo.onChange(callback);

      // Wait for initial trigger
      await vi.waitFor(() => {
        expect(callback).toHaveBeenCalledTimes(1);
      });

      // Clear initial trigger count
      callback.mockClear();

      // Trigger set()
      await repo.set({
        rest: {
          ...initialOptions.rest,
          baseUrl: 'https://updated.example/'
        }
      });

      // Wait for onChange to process
      await vi.waitFor(() => {
        expect(callback).toHaveBeenCalled();
      });

      // ✅ Critical assertion: Should be called EXACTLY ONCE, not twice
      expect(callback).toHaveBeenCalledTimes(1);
      const callbackCalls = callback.mock.calls as Array<[CompleteOptions]>;
      const callbackArg = callbackCalls[0]?.[0];
      expect(callbackArg?.rest.baseUrl).toBe('https://updated.example/');

      // ✅ Verify storage.sync.watchKey was NEVER called (no watcher attached)
      expect(mockStorage.sync.watchKey).not.toHaveBeenCalled();
    });

    it('should emit initial state immediately when onChange is called', async () => {
      const initialOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      initialOptions.rest.vault = 'InitialVault';
      mockStorage.sync.get.mockResolvedValue(initialOptions);

      const callback = vi.fn();
      repo.onChange(callback);

      await vi.waitFor(() => {
        expect(callback).toHaveBeenCalledTimes(1);
      });

      const callbackCalls = callback.mock.calls as Array<[CompleteOptions]>;
      const callbackArg = callbackCalls[0]?.[0];
      expect(callbackArg?.rest.vault).toBe('InitialVault');
    });

    it('should unsubscribe correctly without detaching non-existent watcher', async () => {
      const initialOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      initialOptions.rest.vault = 'InitialVault';
      mockStorage.sync.get.mockResolvedValue(initialOptions);

      const callback = vi.fn();
      const unsubscribe = repo.onChange(callback);

      // Wait for initial trigger
      await vi.waitFor(() => {
        expect(callback).toHaveBeenCalledTimes(1);
      });

      // Unsubscribe
      unsubscribe();

      // Clear and verify no more triggers
      callback.mockClear();
      const newOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      newOptions.rest.baseUrl = 'https://unsubscribed.example/';
      mockStorage.sync.get.mockResolvedValue(newOptions);
      await repo.set({
        rest: {
          ...initialOptions.rest,
          baseUrl: 'https://unsubscribed.example/'
        }
      });

      // Wait a bit to ensure callback is not called
      await new Promise(resolve => setTimeout(resolve, 100));

      // ✅ Should NOT be called after unsubscribe
      expect(callback).not.toHaveBeenCalled();
    });

    it('should notify multiple subscribers when options change', async () => {
      const initialOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      initialOptions.rest.vault = 'MultiVault';
      const updatedOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      updatedOptions.rest.baseUrl = 'https://multi.example/';

      mockStorage.sync.get
        .mockResolvedValueOnce(initialOptions) // subscriber 1 initial
        .mockResolvedValueOnce(initialOptions) // subscriber 2 initial
        .mockResolvedValueOnce(initialOptions) // repo.set merge
        .mockResolvedValueOnce(updatedOptions); // notify listeners payload

      const callback1 = vi.fn();
      const callback2 = vi.fn();

      repo.onChange(callback1);
      repo.onChange(callback2);

      await vi.waitFor(() => {
        expect(callback1).toHaveBeenCalledTimes(1);
        expect(callback2).toHaveBeenCalledTimes(1);
      });

      callback1.mockClear();
      callback2.mockClear();

      await repo.set({
        rest: {
          ...initialOptions.rest,
          baseUrl: 'https://multi.example/'
        }
      });

      await vi.waitFor(() => {
        expect(callback1).toHaveBeenCalledTimes(1);
        expect(callback2).toHaveBeenCalledTimes(1);
      });
      const callback1Calls = callback1.mock.calls as Array<[CompleteOptions]>;
      const callback2Calls = callback2.mock.calls as Array<[CompleteOptions]>;
      const callbackArg1 = callback1Calls[0]?.[0];
      const callbackArg2 = callback2Calls[0]?.[0];
      expect(callbackArg1?.rest.baseUrl).toBe('https://multi.example/');
      expect(callbackArg2?.rest.baseUrl).toBe('https://multi.example/');
    });
  });

  // ===========================
  // get() 测试
  // ===========================
  describe('get()', () => {
    it('should return merged options from storage', async () => {
      const storedOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      storedOptions.rest.baseUrl = 'https://stored.example/';
      mockStorage.sync.get.mockResolvedValue(storedOptions);

      const result = await repo.get();

      expect(mockStorage.sync.get).toHaveBeenCalledWith('options');
      expect(result.rest.baseUrl).toBe('https://stored.example/');
      expect(result.templates.fragment).toBe((DEFAULT_OPTIONS as CompleteOptions).templates.fragment);
      expect(result.domainMappings).toEqual((DEFAULT_OPTIONS as CompleteOptions).domainMappings);
    });

    it('should return default options when storage is empty', async () => {
      mockStorage.sync.get.mockResolvedValue(null);

      const result = await repo.get();

      expect(result).toEqual(DEFAULT_OPTIONS as CompleteOptions);
    });
    it('should merge partial options with defaults when storage has sparse data', async () => {
      mockStorage.sync.get.mockResolvedValue({
        rest: {
          baseUrl: 'https://partial.example/'
        }
      } as Partial<CompleteOptions>);

      const result = await repo.get();

      expect(result.rest.baseUrl).toBe('https://partial.example/');
      expect(result.templates.fragment).toBe((DEFAULT_OPTIONS as CompleteOptions).templates.fragment);
      expect(result.domainMappings).toEqual((DEFAULT_OPTIONS as CompleteOptions).domainMappings);
    });

    it('should throw StorageError when storage.get fails', async () => {
      const failure = new Error('storage unavailable');
      mockStorage.sync.get.mockRejectedValue(failure);

      const attempt = repo.get();

      await expect(attempt).rejects.toBeInstanceOf(StorageError);
      await expect(attempt).rejects.toThrow('Failed to get options from chrome.storage');
    });
  });

  // ===========================
  // set() 测试
  // ===========================
  describe('set()', () => {
    it('should merge partial options and save to storage', async () => {
      const currentOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      currentOptions.rest.baseUrl = 'https://current.example/';
      const partialUpdate = {
        rest: {
          ...currentOptions.rest,
          baseUrl: 'https://updated.example/'
        }
      };

      mockStorage.sync.get.mockResolvedValue(currentOptions);

      await repo.set(partialUpdate);

      expect(mockStorage.sync.set).toHaveBeenCalledWith('options', {
        ...currentOptions,
        ...partialUpdate
      });
    });

    it('should throw StorageError when storage.set fails', async () => {
      const currentOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      const partialUpdate = {
        rest: {
          ...currentOptions.rest,
          baseUrl: 'https://updated.example/'
        }
      };

      mockStorage.sync.get.mockResolvedValue(currentOptions);
      mockStorage.sync.set.mockRejectedValue(new Error('quota exceeded'));

      const attempt = repo.set(partialUpdate);

      await expect(attempt).rejects.toBeInstanceOf(StorageError);
      await expect(attempt).rejects.toThrow('Failed to set options to chrome.storage');
    });

    it('should wrap errors thrown by get() while preparing the payload', async () => {
      const getSpy = vi.spyOn(repo, 'get').mockRejectedValueOnce(new Error('pull failed'));

      const attempt = repo.set({
        rest: {
          ...(DEFAULT_OPTIONS as CompleteOptions).rest,
          baseUrl: 'https://should-not-write.example/'
        }
      });

      await expect(attempt).rejects.toBeInstanceOf(StorageError);
      await expect(attempt).rejects.toThrow('Failed to set options to chrome.storage');

      getSpy.mockRestore();
    });
  });

  describe('immutability & listener safety', () => {
    it('should deliver deep-cloned snapshots to listeners', async () => {
      const initialOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      const updatedOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      updatedOptions.rest.vault = 'ImmutableVault';

      mockStorage.sync.get
        .mockResolvedValueOnce(initialOptions) // initial snapshot for onChange
        .mockResolvedValueOnce(initialOptions) // repo.set -> this.get()
        .mockResolvedValueOnce(updatedOptions) // notifyListeners -> this.get()
        .mockResolvedValueOnce(updatedOptions); // repo.get() after mutation check

      let receivedOptions: CompleteOptions | null = null;
      repo.onChange((options) => {
        receivedOptions = options;
      });

      await vi.waitFor(() => {
        expect(receivedOptions).not.toBeNull();
      });

      receivedOptions = null;

      await repo.set({
        rest: {
          ...initialOptions.rest,
          vault: 'ImmutableVault'
        }
      });

      await vi.waitFor(() => {
        expect(receivedOptions).not.toBeNull();
      });

      const clonedOptions = receivedOptions as unknown as CompleteOptions;
      if (!clonedOptions) {
        throw new Error('Received options missing');
      }
      clonedOptions.rest.vault = 'MUTATED';
      const latest = await repo.get();
      expect(latest.rest.vault).toBe('ImmutableVault');
      expect(latest.rest.vault).not.toBe(clonedOptions.rest.vault);
    });

    it('should continue notifying other listeners when one throws', async () => {
      const initialOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      const updatedOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      updatedOptions.rest.baseUrl = 'https://listener.example/';

      mockStorage.sync.get
        .mockResolvedValueOnce(initialOptions) // faulty listener initial
        .mockResolvedValueOnce(initialOptions) // healthy listener initial
        .mockResolvedValueOnce(initialOptions) // repo.set -> this.get()
        .mockResolvedValueOnce(updatedOptions); // notify listeners payload

      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => undefined);

      const faultyListener = vi.fn(() => {
        throw new Error('listener boom');
      });
      const healthyListener = vi.fn();

      repo.onChange(faultyListener);
      repo.onChange(healthyListener);

      await vi.waitFor(() => {
        expect(faultyListener).toHaveBeenCalledTimes(1);
        expect(healthyListener).toHaveBeenCalledTimes(1);
      });

      faultyListener.mockClear();
      healthyListener.mockClear();
      consoleSpy.mockClear();

      await repo.set({
        rest: {
          ...initialOptions.rest,
          baseUrl: 'https://listener.example/'
        }
      });

      await vi.waitFor(() => {
        expect(healthyListener).toHaveBeenCalledTimes(1);
        expect(faultyListener).toHaveBeenCalledTimes(1);
      });
      expect(consoleSpy).toHaveBeenCalled();

      consoleSpy.mockRestore();
    });
  });

  describe('environment compatibility', () => {
    it('should leverage global structuredClone when available', async () => {
      const globalRef = globalThis as typeof globalThis & { structuredClone?: <T>(value: T) => T };
      const originalStructuredClone = globalRef.structuredClone;

      const structuredCloneSpy = vi.fn(<T>(value: T) => JSON.parse(JSON.stringify(value)) as T);
      globalRef.structuredClone = structuredCloneSpy;

      const currentOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      const updatedUrl = 'https://structured.example/';

      mockStorage.sync.get
        .mockResolvedValueOnce(currentOptions) // initial onChange snapshot
        .mockResolvedValueOnce(currentOptions) // repo.set -> this.get()
        .mockResolvedValueOnce({
          ...currentOptions,
          rest: {
            ...currentOptions.rest,
            baseUrl: updatedUrl
          }
        }); // notify listeners payload

      try {
        const callback = vi.fn();
        repo.onChange(callback);
        await vi.waitFor(() => {
          expect(callback).toHaveBeenCalledTimes(1);
        });
        callback.mockClear();

        await repo.set({
          rest: {
            ...currentOptions.rest,
            baseUrl: updatedUrl
          }
        });

        expect(structuredCloneSpy).toHaveBeenCalled();
      } finally {
        globalRef.structuredClone = originalStructuredClone;
      }
    });

    it('should fall back to JSON cloning when structuredClone is unavailable', async () => {
      const globalRef = globalThis as typeof globalThis & { structuredClone?: <T>(value: T) => T };
      const originalStructuredClone = globalRef.structuredClone;
      Reflect.deleteProperty(globalRef, 'structuredClone');

      const currentOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      const updatedUrl = 'https://json-clone.example/';

      mockStorage.sync.get
        .mockResolvedValueOnce(currentOptions) // repo.set -> this.get()
        .mockResolvedValueOnce({
          ...currentOptions,
          rest: {
            ...currentOptions.rest,
            baseUrl: updatedUrl
          }
        }); // notify listeners payload

      try {
        await repo.set({
          rest: {
            ...currentOptions.rest,
            baseUrl: updatedUrl
          }
        });

        const lastCall = mockStorage.sync.set.mock.calls.at(-1);
        if (!lastCall) {
          throw new Error('Expected storage.set to be called');
        }
        const [, savedOptions] = lastCall;
        expect((savedOptions as CompleteOptions).rest.baseUrl).toBe(updatedUrl);
      } finally {
        globalRef.structuredClone = originalStructuredClone;
      }
    });
  });

  describe('error handling around notifications', () => {
    it('should log errors when notifyListeners fails to fetch options', async () => {
      const currentOptions = cloneOptions(DEFAULT_OPTIONS as CompleteOptions);
      const getSpy = vi
        .spyOn(repo, 'get')
        .mockResolvedValueOnce(currentOptions)
        .mockRejectedValueOnce(new Error('notify failed'));
      const consoleSpy = vi.spyOn(console, 'error').mockImplementation(() => undefined);

      await repo.set({
        rest: {
          ...currentOptions.rest,
          baseUrl: 'https://notify-error.example/'
        }
      });
      await vi.waitFor(() => {
        expect(consoleSpy).toHaveBeenCalled();
      });
      expect(consoleSpy).toHaveBeenCalledWith(
        '[ChromeOptionsRepository] Failed to notify listeners:',
        expect.any(Error)
      );

      consoleSpy.mockRestore();
      getSpy.mockRestore();
    });
  });
});

