        fragmentSaves: DEFAULT_USAGE_STATS.fragmentSaves,
        articleSaves: DEFAULT_USAGE_STATS.articleSaves,
        lastUpdatedISO: DEFAULT_USAGE_STATS.lastUpdatedISO,
        history: []
      });
    });

    section.destroy();
  });
});

