    remove(keys: string | string[], callback?: () => void) {
      const promise = remove(keys);
      if (typeof callback === 'function') {
        void promise.then(() => callback());
        return;
      }
      return promise;
    },
    clear(callback?: () => void) {
      const promise = clear();
      if (typeof callback === 'function') {
        void promise.then(() => callback());
        return;
      }
      return promise;
    }
  } as unknown as chrome.storage.StorageArea;

  const reset = () => {
